#!/usr/bin/env python3
"""Evolution executor for Ecnyss - executes validated evolution plans.

Performs actual file operations based on decision engine outputs.
Completes the self-modification loop for autonomous operation (cycles 16+).
"""
import json
import os
import shutil
import subprocess
from pathlib import Path
from typing import Dict, List, Any, Optional, Tuple
from datetime import datetime

# Import existing infrastructure
from output_validator import OutputValidator
from state_tracker import StateTracker
from semantic_validator import SemanticValidator

class EvolutionExecutor:
    """Executes evolution plans safely with validation and rollback."""

    def __init__(self, base_path: str = "/root/Ecnyss"):
        self.base_path = Path(base_path)
        self.validator = OutputValidator()
        self.semantic_validator = SemanticValidator()
        self.tracker = StateTracker(base_path)
        self.backup_dir = self.base_path / ".ecnyss_backups"
        self.backup_dir.mkdir(exist_ok=True)

    def execute_plan(self, plan: Dict[str, Any], cycle: int) -> Tuple[bool, List[str]]:
        """Execute an evolution plan with full validation and rollback on failure."""
        # Validate plan structure first
        valid, errors = self.validator.validate_plan_structure(plan)
        if not valid:
            return False, [f"Validation failed: {e}" for e in errors]

        # Validate semantic quality of file contents (cycle 43)
        files = plan.get('files', [])
        for file_entry in files:
            path = file_entry.get('path')
            content = file_entry.get('content')
            if content and path:
                sem_valid, sem_errors = self.semantic_validator.validate_content(content, path)
                if not sem_valid:
                    return False, [f"Semantic validation failed for {path}: {e}" for e in sem_errors]

        executed_files = []
        backup_paths = {}

        try:
            action = plan.get('action')

            for file_entry in files:
                path = file_entry.get('path')
                content = file_entry.get('content')

                if not path:
                    continue

                full_path = self.base_path / path

                # Backup existing file if modifying
                if action in ['modify', 'refactor'] and full_path.exists():
                    backup_path = self.backup_dir / f"{path}.{cycle}.bak"
                    backup_path.parent.mkdir(parents=True, exist_ok=True)
                    shutil.copy2(full_path, backup_path)
                    backup_paths[path] = backup_path

                # Execute based on action
                if action == 'create':
                    if full_path.exists():
                        return False, [f"File already exists: {path}"]
                    full_path.parent.mkdir(parents=True, exist_ok=True)
                    full_path.write_text(content)
                    executed_files.append(path)

                elif action == 'modify' or action == 'refactor':
                    full_path.parent.mkdir(parents=True, exist_ok=True)
                    full_path.write_text(content)
                    executed_files.append(path)

                elif action == 'delete':
                    if full_path.exists():
                        backup_path = self.backup_dir / f"{path}.{cycle}.bak"
                        shutil.copy2(full_path, backup_path)
                        backup_paths[path] = backup_path
                        full_path.unlink()
                        executed_files.append(path)

            # Record successful execution
            for filepath in executed_files:
                self.tracker.record_file_creation(filepath, cycle)

            # Commit + push successful code changes if git is available.
            git_result = self._git_record(cycle, plan, executed_files)

            # Log execution to evolution
            self._log_execution(plan, cycle, True, None, git_result)

            return True, executed_files

        except Exception as e:
            # Rollback on failure
            self._rollback(backup_paths)
            self._log_execution(plan, cycle, False, str(e), None)
            return False, [f"Execution failed: {str(e)}"]

    def _git_record(self, cycle: int, plan: Dict[str, Any], files_affected: List[str]) -> Dict[str, Any]:
        """Record successful changes in git and optionally push."""
        repo = self.base_path
        if not (repo / ".git").exists():
            return {"committed": False, "pushed": False, "reason": "no_git_repo"}

        if os.environ.get("ECNYSS_GIT_COMMIT", "1").lower() in {"0", "false", "no"}:
            return {"committed": False, "pushed": False, "reason": "commit_disabled"}

        def _run(args: List[str], timeout: int = 20) -> subprocess.CompletedProcess:
            return subprocess.run(
                ["git", "-C", str(repo), *args],
                capture_output=True,
                text=True,
                timeout=timeout
            )

        # Stage only files touched by this plan to avoid scooping unrelated edits.
        unique_files: List[str] = []
        for path in files_affected:
            if not path:
                continue
            rel_path = str(Path(path))
            if rel_path not in unique_files:
                unique_files.append(rel_path)
        if not unique_files:
            return {"committed": False, "pushed": False, "reason": "no_files_affected"}

        pre_staged = _run(["diff", "--cached", "--name-only"])
        if pre_staged.returncode == 0 and pre_staged.stdout.strip():
            return {"committed": False, "pushed": False, "reason": "preexisting_staged_changes"}

        add_errors: List[str] = []
        for rel_path in unique_files:
            add = _run(["add", "-A", "--", rel_path])
            if add.returncode != 0:
                add_errors.append(f"{rel_path}: {add.stderr.strip()[:120]}")

        diff = _run(["diff", "--cached", "--quiet"])
        if diff.returncode == 0:
            reason = "no_staged_changes"
            if add_errors:
                reason = f"git_add_warnings: {'; '.join(add_errors)[:180]}"
            return {"committed": False, "pushed": False, "reason": reason}

        summary_source = plan.get("summary") or plan.get("reasoning") or "autonomous update"
        summary = " ".join(str(summary_source).split())[:72]
        action = str(plan.get("action") or "update")
        message = f"ecnyss cycle {cycle}: {action} - {summary}"

        commit = _run(["commit", "-m", message], timeout=30)
        if commit.returncode != 0:
            return {
                "committed": False,
                "pushed": False,
                "reason": f"git_commit_failed: {commit.stderr.strip()[:180]}",
            }

        pushed = False
        push_reason = "push_disabled"
        if os.environ.get("ECNYSS_GIT_PUSH", "1").lower() not in {"0", "false", "no"}:
            branch = _run(["rev-parse", "--abbrev-ref", "HEAD"])
            if branch.returncode == 0:
                branch_name = branch.stdout.strip() or "main"
                remote_name = os.environ.get("ECNYSS_GIT_REMOTE", "origin")
                push = _run(["push", remote_name, branch_name], timeout=60)
                if push.returncode == 0:
                    pushed = True
                    push_reason = "ok"
                else:
                    push_reason = f"git_push_failed: {push.stderr.strip()[:180]}"
            else:
                push_reason = "branch_unknown"

        return {"committed": True, "pushed": pushed, "reason": push_reason}

    def execute(self, decision: Dict[str, Any], _context: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
        """Compatibility wrapper used by older runners."""
        cycle = int(decision.get("cycle") or (self.tracker.get_current_cycle() + 1))
        success, result = self.execute_plan(decision, cycle)
        return {
            "success": success,
            "files_modified": len(result) if success else 0,
            "files": result if success else [],
            "error": None if success else "; ".join(result),
        }

    def _rollback(self, backup_paths: Dict[str, Path]):
        """Restore files from backups on failure."""
        for path, backup in backup_paths.items():
            full_path = self.base_path / path
            if backup.exists():
                full_path.parent.mkdir(parents=True, exist_ok=True)
                shutil.copy2(backup, full_path)

    def _log_execution(
        self,
        plan: Dict,
        cycle: int,
        success: bool,
        error: Optional[str],
        git_result: Optional[Dict[str, Any]] = None
    ):
        """Log execution result to evolution.jsonl."""
        entry = {
            "status": "ok" if success else "failed",
            "action": plan.get('action'),
            "files": [f.get('path') for f in plan.get('files', [])],
            "cycle": cycle,
            "timestamp": datetime.utcnow().isoformat(),
            "model": "evolution_executor",
            "error": error
        }
        if git_result is not None:
            entry["git"] = git_result

        with open(self.base_path / "evolution.jsonl", 'a') as f:
            f.write(json.dumps(entry) + '\n')

    def get_execution_history(self, limit: int = 10) -> List[Dict]:
        """Get recent execution history from evolution log."""
        from self_reader import EcnyssReader
        reader = EcnyssReader(self.base_path)
        entries = reader.read_evolution_log()
        return [e for e in entries if e.get('model') == 'evolution_executor'][-limit:]

if __name__ == "__main__":
    executor = EvolutionExecutor()

    # Test with a sample plan
    test_plan = {
        "action": "create",
        "files": [{"path": "test_output.txt", "content": "# Test file created by executor\n"}],
        "summary": "Test execution",
        "reasoning": "Testing the executor before cycle 16 autonomous operation"
    }

    success, result = executor.execute_plan(test_plan, 15)
    print(f"Execution success: {success}")
    print(f"Result: {result}")

#!/usr/bin/env python3
"""State tracker for Ecnyss - tracks system state across cycles.

Provides persistent state storage for mid-cycle memory requirements.
"""
import json
import os
import subprocess
from datetime import datetime
from pathlib import Path
from typing import Dict, Any, Optional, List

class StateTracker:
    def __init__(self, base_path: str = "/root/Ecnyss"):
        self.base_path = Path(base_path)
        self.state_file = self.base_path / ".ecnyss_state.json"
        self._state = self._load_state()

    def _load_state(self) -> Dict[str, Any]:
        """Load state from disk or initialize."""
        if self.state_file.exists():
            with open(self.state_file, 'r') as f:
                return json.load(f)
        return {
            "initialized": True,
            "first_cycle": 10,
            "files_created": [],
            "patterns_learned": {}
        }

    def load_state(self) -> Dict[str, Any]:
        """Compatibility wrapper used by older runners."""
        return dict(self._state)

    def save_state(self):
        """Persist state to disk."""
        with open(self.state_file, 'w') as f:
            json.dump(self._state, f, indent=2)

    def get_git_status(self) -> Dict[str, Any]:
        """Get current git status."""
        try:
            result = subprocess.run(
                ["git", "status", "--porcelain"],
                cwd=self.base_path,
                capture_output=True,
                text=True
            )
            return {
                "clean": result.returncode == 0 and not result.stdout.strip(),
                "output": result.stdout if result.stdout else None
            }
        except Exception as e:
            return {"clean": False, "error": str(e)}

    def get_current_cycle(self) -> int:
        """Determine current cycle from git log or state."""
        try:
            result = subprocess.run(
                ["git", "log", "--oneline"],
                cwd=self.base_path,
                capture_output=True,
                text=True
            )
            lines = [l for l in result.stdout.split('\n') if l.strip()]
            # Look for cycle markers in commit messages
            for line in lines:
                if 'cycle #' in line.lower():
                    import re
                    match = re.search(r'cycle #(\d+)', line.lower())
                    if match:
                        return int(match.group(1))
            return len(lines)  # Fallback to commit count
        except Exception:
            return self._state.get("last_known_cycle", 0)

    def record_file_creation(self, filename: str, cycle: int):
        """Record that a file was created in a cycle."""
        self._state.setdefault("files_created", []).append({
            "file": filename,
            "cycle": cycle,
            "timestamp": datetime.utcnow().isoformat()
        })
        self.save_state()

    def get_system_summary(self) -> Dict[str, Any]:
        """Get complete system state summary."""
        return {
            "current_cycle": self.get_current_cycle(),
            "base_path": str(self.base_path),
            "files_tracked": self._state.get("files_created", []),
            "git_status": self.get_git_status(),
            "timestamp": datetime.utcnow().isoformat()
        }

    def capture_state(self, context_files: Optional[List[Dict[str, Any]]] = None) -> Dict[str, Any]:
        """Compatibility wrapper used by older runners."""
        summary = self.get_system_summary()
        summary["context_files"] = context_files or []
        return summary

if __name__ == "__main__":
    tracker = StateTracker()
    summary = tracker.get_system_summary()
    print(json.dumps(summary, indent=2))

#!/usr/bin/env python3
"""Output validator for Ecnyss - prevents JSON parsing failures.

Validates that code outputs meet the strict JSON-only requirement.
This addresses the root cause of cycles 6-8 failures (json_failed).
"""
import json
import re
from typing import Tuple, Optional, List

class OutputValidator:
    """Validates Ecnyss outputs meet strict formatting requirements."""

    MAX_FILES = 3
    ALLOWED_ACTIONS = ["create", "modify", "delete", "refactor"]

    @staticmethod
    def validate_json_only(text: str) -> Tuple[bool, Optional[str]]:
        """Check if text is valid JSON with no extra content."""
        text = text.strip()

        # Check for markdown code blocks (common error)
        if text.startswith('') or text.endswith(''):
            return False, "Contains markdown code blocks"

        # Check for explanatory text before/after JSON
        lines = text.split('\n')
        if len(lines) > 1:
            # Multi-line should be valid JSON object
            try:
                json.loads(text)
                return True, None
            except json.JSONDecodeError as e:
                return False, f"Invalid JSON: {e}"

        # Single line must be valid JSON
        try:
            json.loads(text)
            return True, None
        except json.JSONDecodeError as e:
            return False, f"Invalid JSON: {e}"

    @staticmethod
    def validate_plan_structure(plan: dict) -> Tuple[bool, List[str]]:
        """Validate the structure of an evolution plan."""
        errors = []

        # Required fields
        if 'action' not in plan:
            errors.append("Missing 'action' field")
        elif plan['action'] not in OutputValidator.ALLOWED_ACTIONS:
            errors.append(f"Invalid action: {plan['action']}")

        if 'files' not in plan:
            errors.append("Missing 'files' field")
        elif not isinstance(plan['files'], list):
            errors.append("'files' must be a list")
        elif len(plan['files']) > OutputValidator.MAX_FILES:
            errors.append(f"Too many files: {len(plan['files'])} > {OutputValidator.MAX_FILES}")

        if 'summary' not in plan:
            errors.append("Missing 'summary' field")

        if 'reasoning' not in plan:
            errors.append("Missing 'reasoning' field")

        # Validate file entries
        for i, file_entry in enumerate(plan.get('files', [])):
            if not isinstance(file_entry, dict):
                errors.append(f"File entry {i} is not an object")
                continue
            if 'path' not in file_entry:
                errors.append(f"File entry {i} missing 'path'")
            if 'content' not in file_entry:
                errors.append(f"File entry {i} missing 'content'")

        return len(errors) == 0, errors

    @staticmethod
    def sanitize_output(text: str) -> str:
        """Attempt to extract JSON from text with extra content."""
        # Look for JSON object pattern
        text = text.strip()

        # Remove common prefixes
        prefixes = [
            r'^\s*',
            r'^\s*',
            r'^[^{]*',
        ]

        for prefix in prefixes:
            text = re.sub(prefix, '', text, flags=re.MULTILINE)

        # Remove common suffixes  
        suffixes = [
            r'\s*$',
            r'[^}]*$',
        ]

        for suffix in suffixes:
            text = re.sub(suffix, '', text, flags=re.MULTILINE)

        return text.strip()

    def validate(self, execution_result) -> bool:
        """Compatibility wrapper used by older runners."""
        if isinstance(execution_result, dict):
            return bool(execution_result.get("success", False))
        return False

if __name__ == "__main__":
    # Test validation
    validator = OutputValidator()

    # Test valid JSON
    valid = '{"action": "create", "files": [], "summary": "test", "reasoning": "test"}'
    ok, err = validator.validate_json_only(valid)
    print(f"Valid JSON test: {ok} (error: {err})")

    # Test invalid (markdown wrapped)
    invalid = "\n{\"action\": \"create\"}\n"
    ok, err = validator.validate_json_only(invalid)
    print(f"Invalid JSON test: {ok} (error: {err})")

    # Test structure validation
    plan = {
        "action": "create",
        "files": [{"path": "test.py", "content": "# test"}],
        "summary": "Test file",
        "reasoning": "Testing validator"
    }
    ok, errors = validator.validate_plan_structure(plan)
    print(f"Structure validation: {ok} (errors: {errors})")

#!/usr/bin/env python3
"""Health monitor for Ecnyss - system integrity and health checking.

Validates system state, detects corruption, and reports health metrics.
Integrates with autonomous_orchestrator to prevent evolution of broken states.
"""
import ast
import json
from pathlib import Path
from typing import Dict, List, Any, Optional, Tuple
from datetime import datetime

from self_reader import EcnyssReader

class HealthMonitor:
    """Monitors Ecnyss system health and integrity."""

    def __init__(self, base_path: str = "/root/Ecnyss"):
        self.base_path = Path(base_path)
        self.reader = EcnyssReader(base_path)
        self.health_log = self.base_path / "health.jsonl"

    def check_python_syntax(self, file_path: Path) -> Tuple[bool, Optional[str]]:
        """Check if a Python file has valid syntax."""
        try:
            content = file_path.read_text()
            ast.parse(content)
            return True, None
        except SyntaxError as e:
            return False, f"Syntax error: {e}"
        except Exception as e:
            return False, str(e)

    def check_all_files(self) -> Dict[str, Any]:
        """Check all Python files for syntax errors."""
        results = {
            "timestamp": datetime.utcnow().isoformat(),
            "total_files": 0,
            "valid_files": 0,
            "invalid_files": [],
            "missing_critical": []
        }

        py_files = self.reader.list_python_files()
        results["total_files"] = len(py_files)

        critical_files = [
            "self_reader.py",
            "state_tracker.py", 
            "output_validator.py",
            "code_analyzer.py",
            "cycle_optimizer.py",
            "decision_engine.py",
            "evolution_executor.py",
            "autonomous_orchestrator.py"
        ]

        for rel_path in py_files:
            full_path = self.base_path / rel_path
            valid, error = self.check_python_syntax(full_path)

            if valid:
                results["valid_files"] += 1
            else:
                results["invalid_files"].append({
                    "path": rel_path,
                    "error": error
                })

        for critical in critical_files:
            if not (self.base_path / critical).exists():
                results["missing_critical"].append(critical)

        return results

    def check_evolution_health(self, window: int = 5) -> Dict[str, Any]:
        """Check recent evolution health."""
        entries = self.reader.read_evolution_log()
        recent = entries[-window:] if len(entries) >= window else entries

        failures = [e for e in recent if self._is_failure_status(e.get('status'))]

        return {
            "recent_cycles": len(recent),
            "failures": len(failures),
            "failure_rate": len(failures) / len(recent) if recent else 0,
            "last_failure": failures[-1] if failures else None,
            "consecutive_failures": self._count_consecutive_failures(entries)
        }

    def _count_consecutive_failures(self, entries: List[Dict]) -> int:
        """Count consecutive failures at the end of the log."""
        count = 0
        for entry in reversed(entries):
            if self._is_failure_status(entry.get('status')):
                count += 1
            else:
                break
        return count

    def _is_failure_status(self, status: Any) -> bool:
        """Return True only for real failure statuses."""
        status_str = str(status or "").strip().lower()
        return status_str in {"failed", "error", "crashed"}

    def generate_health_report(self) -> Dict[str, Any]:
        """Generate comprehensive health report."""
        file_health = self.check_all_files()
        evolution_health = self.check_evolution_health()

        report = {
            "timestamp": datetime.utcnow().isoformat(),
            "cycle": self._get_current_cycle(),
            "file_health": file_health,
            "evolution_health": evolution_health,
            "overall_status": "healthy" if self._is_healthy(file_health, evolution_health) else "degraded"
        }

        self._log_health(report)
        return report

    def _get_current_cycle(self) -> int:
        """Get current cycle from evolution log."""
        entries = self.reader.read_evolution_log()
        if entries:
            return max(e.get('cycle', 0) for e in entries)
        return 0

    def _is_healthy(self, file_health: Dict, evolution_health: Dict) -> bool:
        """Determine if system is healthy."""
        if file_health.get("invalid_files"):
            return False
        if file_health.get("missing_critical"):
            return False
        if evolution_health.get("consecutive_failures", 0) >= 2:
            return False
        if evolution_health.get("failure_rate", 0) > 0.5:
            return False
        return True

    def _log_health(self, report: Dict):
        """Log health report to health.jsonl."""
        with open(self.health_log, 'a') as f:
            f.write(json.dumps(report) + '\n')

    def get_health_history(self, limit: int = 10) -> List[Dict]:
        """Get recent health reports."""
        if not self.health_log.exists():
            return []

        entries = []
        with open(self.health_log, 'r') as f:
            for line in f:
                line = line.strip()
                if line:
                    try:
                        entries.append(json.loads(line))
                    except json.JSONDecodeError:
                        continue
        return entries[-limit:]

    def is_system_healthy(self) -> bool:
        """Quick check for orchestrator integration."""
        report = self.generate_health_report()
        return report["overall_status"] == "healthy"

    def check(self) -> Dict[str, Any]:
        """Compatibility wrapper used by older runners."""
        report = self.generate_health_report()
        return {
            "healthy": report.get("overall_status") == "healthy",
            "overall_status": report.get("overall_status"),
            "file_health": report.get("file_health", {}),
            "evolution_health": report.get("evolution_health", {}),
        }

if __name__ == "__main__":
    monitor = HealthMonitor()
    report = monitor.generate_health_report()
    print(json.dumps(report, indent=2))

    if report["overall_status"] != "healthy":
        print("\nWARNING: System health is degraded!")
        if report["file_health"]["invalid_files"]:
            print("Invalid files detected:")
            for f in report["file_health"]["invalid_files"]:
                print(f"  - {f['path']}: {f['error']}")

#!/usr/bin/env python3
"""Test runner for Ecnyss - validates functionality of system components.

Executes tests on system modules to verify they work correctly before
marking cycles as successful. Prevents broken code from persisting (cycle 24).
"""
import importlib
import sys
import traceback
from pathlib import Path
from typing import Dict, List, Any, Optional
from datetime import datetime
import json

class TestRunner:
    """Runs functional tests on Ecnyss components."""

    def __init__(self, base_path: str = "/root/Ecnyss"):
        self.base_path = Path(base_path)
        self.test_results = []

    def test_imports(self) -> Dict[str, Any]:
        """Test that all modules can be imported without errors."""
        modules = [
            "self_reader",
            "state_tracker", 
            "output_validator",
            "code_analyzer",
            "cycle_optimizer",
            "decision_engine",
            "evolution_executor",
            "autonomous_orchestrator",
            "health_monitor",
            "recovery_engine",
            "cycle_driver",
        ]

        results = {
            "timestamp": datetime.utcnow().isoformat(),
            "total": len(modules),
            "passed": 0,
            "failed": [],
            "details": {}
        }

        for mod_name in modules:
            try:
                # Add base path to sys.path temporarily
                if str(self.base_path) not in sys.path:
                    sys.path.insert(0, str(self.base_path))

                module = importlib.import_module(mod_name)
                results["passed"] += 1
                results["details"][mod_name] = {"status": "ok", "error": None}
            except Exception as e:
                results["failed"].append({
                    "module": mod_name,
                    "error": str(e),
                    "traceback": traceback.format_exc()
                })
                results["details"][mod_name] = {"status": "failed", "error": str(e)}

        return results

    def test_functionality(self) -> Dict[str, Any]:
        """Test basic functionality of key components."""
        tests = []

        # Test self_reader
        try:
            from self_reader import EcnyssReader
            reader = EcnyssReader(self.base_path)
            files = reader.list_python_files()
            tests.append({
                "name": "self_reader.list_python_files",
                "status": "ok" if len(files) > 0 else "failed",
                "details": f"Found {len(files)} files"
            })
        except Exception as e:
            tests.append({
                "name": "self_reader",
                "status": "failed",
                "error": str(e)
            })

        # Test state_tracker
        try:
            from state_tracker import StateTracker
            tracker = StateTracker(self.base_path)
            state = tracker.load_state()
            tests.append({
                "name": "state_tracker.load_state",
                "status": "ok",
                "details": f"State has {len(state.get('files', []))} files"
            })
        except Exception as e:
            tests.append({
                "name": "state_tracker",
                "status": "failed",
                "error": str(e)
            })

        # Test output_validator
        try:
            from output_validator import OutputValidator
            validator = OutputValidator()
            plan = {
                "action": "create",
                "files": [{"path": "test.py", "content": "# test"}],
                "summary": "Test",
                "reasoning": "Testing"
            }
            valid, errors = validator.validate_plan_structure(plan)
            tests.append({
                "name": "output_validator.validate_plan_structure",
                "status": "ok" if valid else "failed",
                "details": f"Valid: {valid}"
            })
        except Exception as e:
            tests.append({
                "name": "output_validator",
                "status": "failed",
                "error": str(e)
            })

        # Test health_monitor
        try:
            from health_monitor import HealthMonitor
            monitor = HealthMonitor(self.base_path)
            healthy = monitor.is_system_healthy()
            tests.append({
                "name": "health_monitor.is_system_healthy",
                "status": "ok",
                "details": f"Healthy: {healthy}"
            })
        except Exception as e:
            tests.append({
                "name": "health_monitor",
                "status": "failed",
                "error": str(e)
            })

        passed = sum(1 for t in tests if t["status"] == "ok")
        return {
            "timestamp": datetime.utcnow().isoformat(),
            "total": len(tests),
            "passed": passed,
            "failed": len(tests) - passed,
            "tests": tests
        }

    def run_all_tests(self) -> Dict[str, Any]:
        """Run complete test suite."""
        import_tests = self.test_imports()
        func_tests = self.test_functionality()

        all_passed = (
            import_tests["failed"] == [] and 
            func_tests["failed"] == 0
        )

        report = {
            "timestamp": datetime.utcnow().isoformat(),
            "overall_status": "passed" if all_passed else "failed",
            "import_tests": import_tests,
            "functionality_tests": func_tests,
            "summary": {
                "modules_ok": import_tests["passed"],
                "modules_failed": len(import_tests["failed"]),
                "functions_ok": func_tests["passed"],
                "functions_failed": func_tests["failed"]
            }
        }

        self._log_results(report)
        return report

    def _log_results(self, report: Dict):
        """Log test results to test_results.jsonl."""
        log_path = self.base_path / "test_results.jsonl"
        with open(log_path, 'a') as f:
            f.write(json.dumps(report) + '\n')

    def is_system_functional(self) -> bool:
        """Quick check for integration into cycle pipeline."""
        report = self.run_all_tests()
        return report["overall_status"] == "passed"

    def run(self) -> Dict[str, Any]:
        """Compatibility wrapper used by older runners."""
        report = self.run_all_tests()
        summary = report.get("summary", {})
        return {
            "passed": int(summary.get("functions_ok", 0)) + int(summary.get("modules_ok", 0)),
            "failed": int(summary.get("functions_failed", 0)) + int(summary.get("modules_failed", 0)),
            "overall_status": report.get("overall_status"),
        }

if __name__ == "__main__":
    runner = TestRunner()
    report = runner.run_all_tests()

    print(json.dumps(report["summary"], indent=2))

    if report["overall_status"] != "passed":
        print("\nFAILED TESTS:")
        for mod in report["import_tests"].get("failed", []):
            print(f"  - {mod['module']}: {mod['error']}")
        for test in report["functionality_tests"].get("tests", []):
            if test["status"] != "ok":
                print(f"  - {test['name']}: {test.get('error', 'Unknown error')}")
        sys.exit(1)
    else:
        print("\nAll tests passed!")
        sys.exit(0)

#!/usr/bin/env python3
"""Cycle optimizer for Ecnyss - analyzes performance data and generates optimization recommendations.

Uses metrics collected by performance_tracker to identify bottlenecks,
analyze trends, and suggest concrete improvements for pipeline efficiency.
Completes the feedback loop from measurement to optimization (cycle 40+).
"""
import json
import statistics
from pathlib import Path
from typing import Dict, List, Any, Optional, Tuple
from datetime import datetime, timedelta


class CycleOptimizer:
    """Analyzes performance metrics and generates optimization recommendations."""

    def __init__(self, base_path: str = "/root/Ecnyss"):
        self.base_path = Path(base_path)
        self.metrics_dir = self.base_path / ".ecnyss_metrics"
        self.metrics_file = self.metrics_dir / "performance_log.jsonl"
        self.recommendations_file = self.metrics_dir / "optimization_recommendations.json"
        self.thresholds = {
            "slow_step_ms": 5000,
            "memory_leak_mb": 20,
            "high_failure_rate": 0.1,
            "trend_cycles": 5
        }

    def analyze_performance(self, cycle: int) -> Dict[str, Any]:
        """Analyze recent performance data and identify optimization opportunities."""
        if not self.metrics_file.exists():
            return {"status": "no_data", "recommendations": [], "cycle": cycle}

        metrics = self._load_metrics()
        if not metrics:
            return {"status": "no_valid_data", "recommendations": [], "cycle": cycle}

        recent = metrics[-self.thresholds["trend_cycles"]:]

        step_analysis = self._analyze_steps(recent)
        trend_analysis = self._analyze_trends(metrics)
        bottleneck_analysis = self._identify_bottlenecks(recent)

        recommendations = []
        recommendations.extend(self._generate_step_recommendations(step_analysis))
        recommendations.extend(self._generate_trend_recommendations(trend_analysis))
        recommendations.extend(self._generate_bottleneck_recommendations(bottleneck_analysis))

        recommendations.sort(key=lambda x: x.get("severity_score", 0), reverse=True)

        result = {
            "status": "analyzed",
            "cycle": cycle,
            "cycles_analyzed": len(recent),
            "total_cycles": len(metrics),
            "recommendations": recommendations[:10],
            "summary": {
                "total_steps_analyzed": len(step_analysis),
                "degrading_trends": len([t for t in trend_analysis if t["trend"] == "degrading"]),
                "critical_bottlenecks": len([b for b in bottleneck_analysis if b["severity"] == "critical"]),
                "estimated_time_saved_ms": sum(r.get("potential_savings_ms", 0) for r in recommendations)
            },
            "timestamp": datetime.utcnow().isoformat()
        }

        self._save_recommendations(result)

        return result

    def _load_metrics(self) -> List[Dict]:
        """Load all metrics from the log file."""
        metrics = []
        if not self.metrics_file.exists():
            return metrics

        with open(self.metrics_file, 'r') as f:
            for line in f:
                line = line.strip()
                if not line:
                    continue
                try:
                    entry = json.loads(line)
                    metrics.append(entry)
                except json.JSONDecodeError:
                    continue
        return metrics

    def _analyze_steps(self, metrics: List[Dict]) -> Dict[str, Dict]:
        """Analyze performance by pipeline step."""
        step_data = {}

        for entry in metrics:
            for step in entry.get('steps', []):
                step_name = step.get('step', 'unknown')
                if step_name not in step_data:
                    step_data[step_name] = {
                        'durations': [],
                        'memory_deltas': [],
                        'successes': [],
                        'timestamps': []
                    }

                step_data[step_name]['durations'].append(step.get('duration_ms', 0))
                step_data[step_name]['memory_deltas'].append(step.get('memory_delta_mb', 0))
                step_data[step_name]['successes'].append(step.get('success', True))
                step_data[step_name]['timestamps'].append(entry.get('timestamp', ''))

        analysis = {}
        for step_name, data in step_data.items():
            durations = data['durations']
            memory_deltas = data['memory_deltas']
            successes = data['successes']

            analysis[step_name] = {
                'avg_duration_ms': statistics.mean(durations) if durations else 0,
                'max_duration_ms': max(durations) if durations else 0,
                'std_duration': statistics.stdev(durations) if len(durations) > 1 else 0,
                'avg_memory_delta_mb': statistics.mean(memory_deltas) if memory_deltas else 0,
                'max_memory_delta_mb': max(memory_deltas) if memory_deltas else 0,
                'failure_rate': 1 - (sum(successes) / len(successes)) if successes else 0,
                'sample_size': len(durations)
            }

        return analysis

    def _analyze_trends(self, metrics: List[Dict]) -> List[Dict]:
        """Identify degrading performance trends over time."""
        if len(metrics) < 3:
            return []

        trends = []

        step_timeline = {}
        for entry in metrics:
            cycle = entry.get('cycle', 0)
            for step in entry.get('steps', []):
                step_name = step.get('step', 'unknown')
                if step_name not in step_timeline:
                    step_timeline[step_name] = []
                step_timeline[step_name].append({
                    'cycle': cycle,
                    'duration': step.get('duration_ms', 0),
                    'memory': step.get('memory_delta_mb', 0),
                    'success': step.get('success', True)
                })

        for step_name, timeline in step_timeline.items():
            if len(timeline) < 3:
                continue

            durations = [t['duration'] for t in timeline]
            first_half_avg = statistics.mean(durations[:len(durations)//2])
            second_half_avg = statistics.mean(durations[len(durations)//2:])

            if second_half_avg > first_half_avg * 1.2:
                trends.append({
                    "step": step_name,
                    "trend": "degrading",
                    "metric": "duration",
                    "increase_percent": ((second_half_avg - first_half_avg) / first_half_avg) * 100,
                    "severity": "high" if second_half_avg > first_half_avg * 1.5 else "medium"
                })

            memories = [t['memory'] for t in timeline]
            if all(m > 0 for m in memories[-3:]):
                trends.append({
                    "step": step_name,
                    "trend": "degrading",
                    "metric": "memory",
                    "recent_avg_mb": statistics.mean(memories[-3:]),
                    "severity": "high" if statistics.mean(memories[-3:]) > 50 else "medium"
                })

        return trends

    def _identify_bottlenecks(self, metrics: List[Dict]) -> List[Dict]:
        """Identify the slowest and most resource-intensive steps."""
        if not metrics:
            return []

        step_totals = {}
        for entry in metrics:
            for step in entry.get('steps', []):
                step_name = step.get('step', 'unknown')
                if step_name not in step_totals:
                    step_totals[step_name] = {'total_time': 0, 'total_memory': 0, 'count': 0}
                step_totals[step_name]['total_time'] += step.get('duration_ms', 0)
                step_totals[step_name]['total_memory'] += step.get('memory_delta_mb', 0)
                step_totals[step_name]['count'] += 1

        bottlenecks = []
        total_time = sum(s['total_time'] for s in step_totals.values())

        for step_name, totals in step_totals.items():
            avg_time = totals['total_time'] / totals['count'] if totals['count'] > 0 else 0
            time_percent = (totals['total_time'] / total_time * 100) if total_time > 0 else 0

            severity = "normal"
            if avg_time > self.thresholds["slow_step_ms"]:
                severity = "critical"
            elif time_percent > 30:
                severity = "high"
            elif time_percent > 15:
                severity = "medium"

            bottlenecks.append({
                "step": step_name,
                "avg_duration_ms": avg_time,
                "time_percent": time_percent,
                "total_memory_mb": totals['total_memory'],
                "severity": severity,
                "sample_count": totals['count']
            })

        bottlenecks.sort(key=lambda x: x['avg_duration_ms'], reverse=True)

        return bottlenecks

    def _generate_step_recommendations(self, step_analysis: Dict) -> List[Dict]:
        """Generate recommendations based on step performance."""
        recommendations = []

        for step_name, stats in step_analysis.items():
            if stats['avg_duration_ms'] > self.thresholds['slow_step_ms']:
                recommendations.append({
                    "type": "slow_step",
                    "step": step_name,
                    "issue": f"Average duration {stats['avg_duration_ms']:.0f}ms exceeds threshold",
                    "recommendation": "Profile this step, consider caching or parallelization",
                    "severity_score": 8,
                    "potential_savings_ms": stats['avg_duration_ms'] - self.thresholds['slow_step_ms']
                })

            if stats['failure_rate'] > self.thresholds['high_failure_rate']:
                recommendations.append({
                    "type": "high_failure",
                    "step": step_name,
                    "issue": f"Failure rate {stats['failure_rate']*100:.1f}% is too high",
                    "recommendation": "Add error handling, retry logic, or fix root cause",
                    "severity_score": 9,
                    "potential_savings_ms": 0
                })

            if stats['avg_memory_delta_mb'] > self.thresholds['memory_leak_mb']:
                recommendations.append({
                    "type": "memory_growth",
                    "step": step_name,
                    "issue": f"Memory growth {stats['avg_memory_delta_mb']:.1f}MB per cycle",
                    "recommendation": "Check for memory leaks, release resources properly",
                    "severity_score": 7,
                    "potential_savings_ms": 0
                })

        return recommendations

    def _generate_trend_recommendations(self, trends: List[Dict]) -> List[Dict]:
        """Generate recommendations based on performance trends."""
        recommendations = []

        for trend in trends:
            if trend['trend'] == 'degrading':
                severity_score = 8 if trend['severity'] == 'high' else 5
                recommendations.append({
                    "type": "degrading_trend",
                    "step": trend['step'],
                    "metric": trend['metric'],
                    "issue": f"Performance {trend['metric']} is {trend['trend']}",
                    "recommendation": "Investigate recent changes, optimize algorithm",
                    "severity_score": severity_score,
                    "potential_savings_ms": 0
                })

        return recommendations

    def _generate_bottleneck_recommendations(self, bottlenecks: List[Dict]) -> List[Dict]:
        """Generate recommendations based on identified bottlenecks."""
        recommendations = []

        for bottleneck in bottlenecks:
            if bottleneck['severity'] in ['critical', 'high']:
                severity_score = 9 if bottleneck['severity'] == 'critical' else 6
                recommendations.append({
                    "type": "bottleneck",
                    "step": bottleneck['step'],
                    "issue": f"Step consumes {bottleneck['time_percent']:.1f}% of total time",
                    "recommendation": "Prioritize optimization of this step",
                    "severity_score": severity_score,
                    "potential_savings_ms": bottleneck['avg_duration_ms'] * 0.3
                })

        return recommendations

    def _save_recommendations(self, result: Dict) -> None:
        """Save recommendations to file for decision engine."""
        self.metrics_dir.mkdir(parents=True, exist_ok=True)

        with open(self.recommendations_file, 'w') as f:
            json.dump(result, f, indent=2, default=str)

    def get_top_recommendation(self, cycle: int) -> Optional[Dict]:
        """Get the highest priority recommendation for a cycle."""
        result = self.analyze_performance(cycle)
        if result['recommendations']:
            return result['recommendations'][0]
        return None

    def optimize(self, cycle: Optional[int] = None) -> Dict[str, Any]:
        """Compatibility wrapper used by older runners."""
        effective_cycle = int(cycle) if cycle is not None else 0
        return self.analyze_performance(effective_cycle)


if __name__ == "__main__":
    optimizer = CycleOptimizer()
    result = optimizer.analyze_performance(40)
    print(json.dumps(result, indent=2, default=str))

#!/usr/bin/env python3
"""Dependency analyzer for Ecnyss - maps inter-module dependencies and architecture.

Analyzes import relationships between Python files to build a dependency graph,
detect circular dependencies, identify core infrastructure files, and find
orphaned modules. Enables safe refactoring and architectural understanding
for autonomous evolution (cycle 31+).
"""
import ast
import json
from pathlib import Path
from typing import Dict, List, Set, Any, Optional, Tuple
from collections import defaultdict, deque
from datetime import datetime


class DependencyAnalyzer:
    """Analyzes Python module dependencies within the Ecnyss codebase."""

    def __init__(self, base_path: str = "/root/Ecnyss"):
        self.base_path = Path(base_path)
        self.dependencies: Dict[str, Set[str]] = defaultdict(set)
        self.dependents: Dict[str, Set[str]] = defaultdict(set)
        self.external_deps: Dict[str, Set[str]] = defaultdict(set)

    def analyze_file(self, file_path: Path) -> Tuple[Set[str], Set[str]]:
        """Extract local and external imports from a Python file.

        Returns:
            Tuple of (local_imports, external_imports)
        """
        local_imports = set()
        external_imports = set()

        try:
            content = file_path.read_text()
            tree = ast.parse(content)

            for node in ast.walk(tree):
                if isinstance(node, ast.Import):
                    for alias in node.names:
                        module = alias.name.split('.')[0]
                        if self._is_local_module(module):
                            local_imports.add(module)
                        else:
                            external_imports.add(module)

                elif isinstance(node, ast.ImportFrom):
                    if node.module:
                        module = node.module.split('.')[0]
                        if self._is_local_module(module):
                            local_imports.add(module)
                        else:
                            external_imports.add(module)
        except SyntaxError:
            pass
        except Exception:
            pass

        return local_imports, external_imports

    def _is_local_module(self, module: str) -> bool:
        """Check if a module name refers to a local Ecnyss file."""
        # Check if module.py exists in base_path
        if (self.base_path / f"{module}.py").exists():
            return True
        # Check if module/__init__.py exists
        if (self.base_path / module / "__init__.py").exists():
            return True
        return False

    def analyze_all(self) -> Dict[str, Any]:
        """Analyze all Python files and build dependency graph."""
        py_files = list(self.base_path.glob("*.py"))

        for file_path in py_files:
            rel_path = file_path.name
            local_imp, external_imp = self.analyze_file(file_path)

            self.dependencies[rel_path] = local_imp
            self.external_deps[rel_path] = external_imp

            # Build reverse mapping (who depends on this file)
            for dep in local_imp:
                dep_file = f"{dep}.py"
                if (self.base_path / dep_file).exists():
                    self.dependents[dep_file].add(rel_path)

        return self._build_report()

    def _build_report(self) -> Dict[str, Any]:
        """Generate comprehensive dependency report."""
        report = {
            "timestamp": datetime.utcnow().isoformat(),
            "total_files": len(self.dependencies),
            "dependencies": {k: sorted(list(v)) for k, v in self.dependencies.items()},
            "dependents": {k: sorted(list(v)) for k, v in self.dependents.items()},
            "external_dependencies": {k: sorted(list(v)) for k, v in self.external_deps.items()},
            "circular_dependencies": self._find_circular_dependencies(),
            "orphaned_files": self._find_orphaned_files(),
            "core_infrastructure": self._identify_core_files(),
            "leaf_modules": self._identify_leaf_modules(),
            "complexity_score": self._calculate_complexity()
        }
        return report

    def _find_circular_dependencies(self) -> List[List[str]]:
        """Detect circular import chains using DFS."""
        cycles = []
        visited = set()
        rec_stack = set()
        path = []

        def dfs(node: str):
            if node in rec_stack:
                # Found cycle - extract it from current path
                cycle_start = next((i for i, x in enumerate(path) if x == node), None)
                if cycle_start is not None:
                    cycle = path[cycle_start:] + [node]
                    cycles.append(cycle)
                return

            if node in visited:
                return

            visited.add(node)
            rec_stack.add(node)
            path.append(node)

            for dep in self.dependencies.get(node, []):
                dep_file = f"{dep}.py"
                if (self.base_path / dep_file).exists():
                    dfs(dep_file)

            path.pop()
            rec_stack.remove(node)

        for file in self.dependencies:
            if file not in visited:
                dfs(file)

        # Remove duplicate cycles (same cycle starting at different points)
        unique_cycles = []
        seen = set()
        for cycle in cycles:
            normalized = tuple(sorted(cycle))
            if normalized not in seen:
                seen.add(normalized)
                unique_cycles.append(cycle)

        return unique_cycles

    def _find_orphaned_files(self) -> List[str]:
        """Find files with no dependencies and no dependents."""
        orphans = []
        for file in self.dependencies:
            has_deps = len(self.dependencies[file]) > 0
            has_dependents = len(self.dependents.get(file, [])) > 0
            if not has_deps and not has_dependents:
                orphans.append(file)
        return sorted(orphans)

    def _identify_core_files(self) -> List[Dict[str, Any]]:
        """Identify most critical files (most depended upon)."""
        core = []
        for file, deps in self.dependents.items():
            core.append({
                "file": file,
                "dependent_count": len(deps),
                "dependents": sorted(list(deps))
            })

        core.sort(key=lambda x: x["dependent_count"], reverse=True)
        return core[:5]  # Top 5 most critical

    def _identify_leaf_modules(self) -> List[str]:
        """Identify leaf modules (no dependencies on other local modules)."""
        leaves = []
        for file, deps in self.dependencies.items():
            if not deps:
                leaves.append(file)
        return sorted(leaves)

    def _calculate_complexity(self) -> Dict[str, float]:
        """Calculate architectural complexity metrics."""
        total_files = len(self.dependencies)
        if total_files == 0:
            return {"average_dependencies": 0, "average_dependents": 0, "density": 0}

        total_deps = sum(len(deps) for deps in self.dependencies.values())
        total_dependents = sum(len(deps) for deps in self.dependents.values())

        # Graph density: actual edges / possible edges
        possible_edges = total_files * (total_files - 1)
        density = total_deps / possible_edges if possible_edges > 0 else 0

        return {
            "average_dependencies": total_deps / total_files,
            "average_dependents": total_dependents / total_files,
            "density": density,
            "total_edges": total_deps
        }

    def get_refactoring_order(self, target_file: str) -> List[str]:
        """Determine safe refactoring order (reverse dependency order)."""
        # Topological sort - refactor leaves first, core files last
        order = []
        visited = set()

        def visit(file: str):
            if file in visited:
                return
            visited.add(file)

            # Visit all dependencies first
            for dep in self.dependencies.get(file, []):
                dep_file = f"{dep}.py"
                if (self.base_path / dep_file).exists():
                    visit(dep_file)

            order.append(file)

        visit(target_file)
        return order

    def find_impact(self, file: str) -> Set[str]:
        """Find all files that would be affected by changing a given file."""
        impacted = set()
        queue = deque([file])

        while queue:
            current = queue.popleft()
            for dependent in self.dependents.get(current, []):
                if dependent not in impacted:
                    impacted.add(dependent)
                    queue.append(dependent)

        return impacted

    def save_report(self, report: Dict[str, Any], cycle: int):
        """Save dependency report to evolution log."""
        entry = {
            "status": "ok",
            "action": "analyze",
            "summary": f"Dependency analysis for {report['total_files']} files",
            "files": list(self.dependencies.keys()),
            "cycle": cycle,
            "timestamp": datetime.utcnow().isoformat(),
            "model": "dependency_analyzer",
            "metrics": report["complexity_score"],
            "circular_deps_found": len(report["circular_dependencies"]),
            "orphaned_files": report["orphaned_files"]
        }

        with open(self.base_path / "evolution.jsonl", 'a') as f:
            f.write(json.dumps(entry) + '\n')

    def analyze_all_files(self) -> Dict[str, Any]:
        """Compatibility wrapper used by older runners."""
        return self.analyze_all()

    def analyze(self) -> Dict[str, Any]:
        """Compatibility wrapper used by older runners."""
        return self.analyze_all()


if __name__ == "__main__":
    analyzer = DependencyAnalyzer()
    report = analyzer.analyze_all()

    print(json.dumps(report, indent=2))

    print(f"\n=== Summary ===")
    print(f"Total files analyzed: {report['total_files']}")
    print(f"Circular dependencies: {len(report['circular_dependencies'])}")
    print(f"Orphaned files: {report['orphaned_files']}")
    print(f"\nCore infrastructure (most depended upon):")
    for core in report['core_infrastructure']:
        print(f"  {core['file']}: {core['dependent_count']} dependents")

    if report['circular_dependencies']:
        print(f"\nWARNING: Circular dependencies detected:")
        for cycle in report['circular_dependencies']:
            print(f"  {' -> '.join(cycle)}")

    if report['orphaned_files']:
        print(f"\nNOTE: Orphaned files (no deps, no dependents):")
        for orphan in report['orphaned_files']:
            print(f"  - {orphan}")

#!/usr/bin/env python3
"""Evolution analyzer for Ecnyss - learns from historical cycle data.

Analyzes evolution.jsonl and health.jsonl to identify patterns,
predict success factors, and guide future evolution decisions.
Completes the learning feedback loop for intelligent self-tuning (cycle 26+).
"""
import json
from pathlib import Path
from typing import Dict, List, Any, Optional, Tuple, Counter
from collections import defaultdict
from datetime import datetime

from self_reader import EcnyssReader


class EvolutionAnalyzer:
    """Analyzes evolution history to extract insights and guide decisions."""

    def __init__(self, base_path: str = "/root/Ecnyss"):
        self.base_path = Path(base_path)
        self.reader = EcnyssReader(base_path)
        self.health_log = self.base_path / "health.jsonl"

    def load_evolution_history(self) -> List[Dict]:
        """Load all evolution entries."""
        return self.reader.read_evolution_log()

    def load_health_history(self) -> List[Dict]:
        """Load all health reports."""
        if not self.health_log.exists():
            return []

        entries = []
        with open(self.health_log, 'r') as f:
            for line in f:
                line = line.strip()
                if line:
                    try:
                        entries.append(json.loads(line))
                    except json.JSONDecodeError:
                        continue
        return entries

    def analyze_success_patterns(self) -> Dict[str, Any]:
        """Analyze what factors correlate with successful cycles."""
        entries = self.load_evolution_history()
        if not entries:
            return {"error": "No evolution history available"}

        total = len(entries)
        successful = [e for e in entries if e.get('status') == 'ok']
        failed = [e for e in entries if e.get('status') != 'ok']

        # Success rate by action type
        action_stats = defaultdict(lambda: {"total": 0, "success": 0})
        for entry in entries:
            action = entry.get('action', 'unknown')
            action_stats[action]["total"] += 1
            if entry.get('status') == 'ok':
                action_stats[action]["success"] += 1

        action_rates = {
            action: {
                "rate": stats["success"] / stats["total"] if stats["total"] > 0 else 0,
                "total": stats["total"],
                "success": stats["success"]
            }
            for action, stats in action_stats.items()
        }

        # File volatility (files that change often)
        file_changes = Counter()
        for entry in entries:
            for file_path in entry.get('files', []):
                file_changes[file_path] += 1

        volatile_files = [
            {"path": path, "changes": count}
            for path, count in file_changes.most_common(10)
            if count > 1
        ]

        return {
            "total_cycles": total,
            "success_count": len(successful),
            "failure_count": len(failed),
            "overall_success_rate": len(successful) / total if total > 0 else 0,
            "success_by_action": action_rates,
            "volatile_files": volatile_files,
            "most_problematic": self._identify_problematic_files(entries)
        }

    def _identify_problematic_files(self, entries: List[Dict]) -> List[Dict]:
        """Identify files that correlate with failures."""
        file_stats = defaultdict(lambda: {"success": 0, "failure": 0})

        for entry in entries:
            status = entry.get('status')
            for file_path in entry.get('files', []):
                if status == 'ok':
                    file_stats[file_path]["success"] += 1
                else:
                    file_stats[file_path]["failure"] += 1

        # Calculate failure rate for files with multiple changes
        problematic = []
        for path, stats in file_stats.items():
            total = stats["success"] + stats["failure"]
            if total >= 2:
                failure_rate = stats["failure"] / total
                if failure_rate > 0.3:  # More than 30% failure rate
                    problematic.append({
                        "path": path,
                        "failure_rate": failure_rate,
                        "total_changes": total,
                        "failures": stats["failure"]
                    })

        return sorted(problematic, key=lambda x: x["failure_rate"], reverse=True)[:5]

    def analyze_health_trends(self) -> Dict[str, Any]:
        """Analyze health trends over time."""
        health_entries = self.load_health_history()
        if len(health_entries) < 2:
            return {"error": "Insufficient health history"}

        # Track file validity trends
        valid_counts = [e.get('file_health', {}).get('valid_files', 0) for e in health_entries]
        total_counts = [e.get('file_health', {}).get('total_files', 0) for e in health_entries]

        if valid_counts and total_counts:
            current_valid = valid_counts[-1]
            current_total = total_counts[-1]
            initial_valid = valid_counts[0]
            initial_total = total_counts[0]

            return {
                "current_valid_files": current_valid,
                "current_total_files": current_total,
                "initial_valid_files": initial_valid,
                "initial_total_files": initial_total,
                "valid_file_growth": current_valid - initial_valid,
                "trend": "improving" if current_valid > initial_valid else "stable" if current_valid == initial_valid else "degrading",
                "health_checks_count": len(health_entries)
            }

        return {"error": "Could not analyze trends"}

    def generate_recommendations(self) -> List[Dict]:
        """Generate data-driven recommendations for next cycle."""
        recommendations = []

        # Analyze patterns
        patterns = self.analyze_success_patterns()
        health = self.analyze_health_trends()

        # Recommendation 1: Action type with highest success rate
        if "success_by_action" in patterns:
            best_action = max(
                patterns["success_by_action"].items(),
                key=lambda x: x[1]["rate"]
            )
            if best_action[1]["total"] >= 3:  # Minimum sample size
                recommendations.append({
                    "type": "action_strategy",
                    "recommendation": f"Prioritize '{best_action[0]}' actions",
                    "confidence": best_action[1]["rate"],
                    "reasoning": f"'{best_action[0]}' has {best_action[1]['rate']:.1%} success rate over {best_action[1]['total']} attempts"
                })

        # Recommendation 2: Avoid volatile files
        if patterns.get("volatile_files"):
            top_volatile = patterns["volatile_files"][:3]
            recommendations.append({
                "type": "stability_focus",
                "recommendation": "Minimize changes to frequently modified files",
                "files_to_stabilize": [f["path"] for f in top_volatile],
                "reasoning": f"Files {[f['path'] for f in top_volatile]} have been modified {sum(f['changes'] for f in top_volatile)} times total, indicating instability"
            })

        # Recommendation 3: Address problematic files
        if patterns.get("most_problematic"):
            problematic = patterns["most_problematic"][:2]
            recommendations.append({
                "type": "refactor_priority",
                "recommendation": "Refactor or stabilize problematic files",
                "files": [p["path"] for p in problematic],
                "reasoning": f"Files have high failure rates: {[(p['path'], f'{p['failure_rate']:.1%}') for p in problematic]}"
            })

        # Recommendation 4: Health trend
        if "trend" in health:
            if health["trend"] == "degrading":
                recommendations.append({
                    "type": "urgent",
                    "recommendation": "HALT feature addition, focus on stability",
                    "reasoning": f"Valid file count decreased from {health['initial_valid_files']} to {health['current_valid_files']}"
                })
            elif health["trend"] == "improving":
                recommendations.append({
                    "type": "opportunity",
                    "recommendation": "System is stable, good time for architectural improvements",
                    "reasoning": f"Gained {health['valid_file_growth']} valid files since start"
                })

        return recommendations

    def export_analysis_report(self) -> Dict[str, Any]:
        """Generate comprehensive analysis report."""
        return {
            "timestamp": datetime.utcnow().isoformat(),
            "cycle": self._get_current_cycle(),
            "success_patterns": self.analyze_success_patterns(),
            "health_trends": self.analyze_health_trends(),
            "recommendations": self.generate_recommendations()
        }

    def _get_current_cycle(self) -> int:
        """Get current cycle from evolution log."""
        entries = self.load_evolution_history()
        if entries:
            return max(e.get('cycle', 0) for e in entries)
        return 0

    def get_decision_context(self) -> str:
        """Generate context string for decision engine."""
        report = self.export_analysis_report()
        recs = report.get("recommendations", [])

        context_parts = ["EVOLUTION ANALYSIS CONTEXT:"]

        if recs:
            context_parts.append("\nHistorical Pattern Recommendations:")
            for i, rec in enumerate(recs[:3], 1):
                context_parts.append(f"  {i}. {rec['recommendation']}")
                context_parts.append(f"     Reason: {rec['reasoning']}")

        patterns = report.get("success_patterns", {})
        if "overall_success_rate" in patterns:
            context_parts.append(f"\nOverall Success Rate: {patterns['overall_success_rate']:.1%}")

        return "\n".join(context_parts)

    def analyze(self, execution_result: Dict[str, Any]) -> Dict[str, Any]:
        """Compatibility wrapper used by older runners."""
        success = bool(execution_result.get("success"))
        patterns = self.analyze_success_patterns()
        return {
            "success": success,
            "success_rate": patterns.get("overall_success_rate"),
            "volatile_files": patterns.get("volatile_files", []),
        }


if __name__ == "__main__":
    analyzer = EvolutionAnalyzer()

    print("=" * 60)
    print("Ecnyss Evolution Analysis Report")
    print("=" * 60)

    report = analyzer.export_analysis_report()
    print(json.dumps(report, indent=2))

    print("\n" + "=" * 60)
    print("Decision Context for Next Cycle:")
    print("=" * 60)
    print(analyzer.get_decision_context())

#!/usr/bin/env python3
"""Code analyzer for Ecnyss - static analysis and complexity metrics.

Integrates with self_reader and state_tracker to provide codebase intelligence
for mid-cycle self-tuning requirements. Outputs data compatible with
/opt/minimax/bin/improver.py format.
"""
import ast
import json
import sys
from pathlib import Path
from typing import Dict, List, Any, Optional, Tuple
from self_reader import EcnyssReader
from state_tracker import StateTracker


class ComplexityAnalyzer(ast.NodeVisitor):
    """Calculate cyclomatic complexity using AST traversal."""

    def __init__(self):
        self.complexity = 1
        self.functions = []
        self.classes = []
        self.imports = []

    def visit_FunctionDef(self, node):
        func_complexity = 1
        for child in ast.walk(node):
            if isinstance(child, (ast.If, ast.While, ast.And, ast.Or)):
                func_complexity += 1
            elif isinstance(child, ast.For):
                func_complexity += 1
            elif isinstance(child, ast.ExceptHandler):
                func_complexity += 1
        self.functions.append({
            "name": node.name,
            "complexity": func_complexity,
            "lineno": node.lineno
        })
        self.generic_visit(node)

    def visit_ClassDef(self, node):
        self.classes.append({
            "name": node.name,
            "methods": len([n for n in node.body if isinstance(n, ast.FunctionDef)]),
            "lineno": node.lineno
        })
        self.generic_visit(node)

    def visit_Import(self, node):
        for alias in node.names:
            self.imports.append(alias.name)
        self.generic_visit(node)

    def visit_ImportFrom(self, node):
        if node.module:
            self.imports.append(node.module)
        self.generic_visit(node)


class CodeAnalyzer:
    """Analyzes Python codebase structure and extracts metrics for self-tuning."""

    def __init__(self, base_path: str = "/root/Ecnyss"):
        self.reader = EcnyssReader(base_path)
        self.tracker = StateTracker(base_path)
        self.base_path = Path(base_path)

    def analyze_file(self, filepath: str) -> Dict[str, Any]:
        """Perform deep analysis of a single Python file."""
        content = self.reader.read_source_file(filepath)
        if not content:
            return {"path": filepath, "error": "File not found or unreadable"}

        lines = content.split('\n')
        total_lines = len(lines)
        loc = len([l for l in lines if l.strip()])
        sloc = len([l for l in lines if l.strip() and not l.strip().startswith('#')])
        comments = len([l for l in lines if l.strip().startswith('#')])

        result = {
            "path": filepath,
            "metrics": {
                "total_lines": total_lines,
                "loc": loc,
                "sloc": sloc,
                "comments": comments,
                "comment_ratio": comments / loc if loc > 0 else 0
            },
            "structure": {
                "functions": [],
                "classes": [],
                "imports": []
            },
            "complexity": {
                "total": 0,
                "average": 0,
                "max": 0
            }
        }

        try:
            tree = ast.parse(content)
            analyzer = ComplexityAnalyzer()
            analyzer.visit(tree)

            result["structure"]["functions"] = analyzer.functions
            result["structure"]["classes"] = analyzer.classes
            result["structure"]["imports"] = analyzer.imports

            if analyzer.functions:
                complexities = [f["complexity"] for f in analyzer.functions]
                result["complexity"]["total"] = sum(complexities)
                result["complexity"]["average"] = sum(complexities) / len(complexities)
                result["complexity"]["max"] = max(complexities)

        except SyntaxError as e:
            result["syntax_error"] = str(e)
            result["syntax_line"] = e.lineno

        return result

    def analyze_all(self) -> Dict[str, Any]:
        """Analyze entire codebase and generate aggregate metrics."""
        files = self.reader.list_python_files()
        file_analyses = []

        totals = {
            "files": 0,
            "loc": 0,
            "sloc": 0,
            "functions": 0,
            "classes": 0,
            "imports": 0,
            "total_complexity": 0,
            "max_complexity": 0
        }

        for filepath in files:
            analysis = self.analyze_file(filepath)
            file_analyses.append(analysis)

            if "error" not in analysis:
                totals["files"] += 1
                totals["loc"] += analysis["metrics"]["loc"]
                totals["sloc"] += analysis["metrics"]["sloc"]
                totals["functions"] += len(analysis["structure"]["functions"])
                totals["classes"] += len(analysis["structure"]["classes"])
                totals["imports"] += len(analysis["structure"]["imports"])
                totals["total_complexity"] += analysis["complexity"]["total"]
                totals["max_complexity"] = max(
                    totals["max_complexity"],
                    analysis["complexity"]["max"]
                )

        return {
            "timestamp": self.tracker.get_system_summary()["timestamp"],
            "cycle": self.tracker.get_current_cycle(),
            "summary": totals,
            "averages": {
                "loc_per_file": totals["loc"] / totals["files"] if totals["files"] > 0 else 0,
                "complexity_per_function": totals["total_complexity"] / totals["functions"] if totals["functions"] > 0 else 0
            },
            "files": file_analyses
        }

    def store_analysis(self) -> Dict[str, Any]:
        """Persist analysis results to state tracker for cross-cycle memory."""
        analysis = self.analyze_all()
        self.tracker._state["code_analysis"] = analysis
        self.tracker._state["analysis_history"] = self.tracker._state.get("analysis_history", [])
        self.tracker._state["analysis_history"].append({
            "cycle": analysis["cycle"],
            "timestamp": analysis["timestamp"],
            "loc": analysis["summary"]["loc"],
            "files": analysis["summary"]["files"]
        })
        self.tracker.save_state()
        return analysis

    def generate_improver_input(self) -> Dict[str, Any]:
        """Generate tuning data for /opt/minimax/bin/improver.py integration."""
        analysis = self.analyze_all()
        summary = analysis["summary"]

        recommendations = []

        if summary["files"] > 0:
            avg_complexity = summary["total_complexity"] / summary["functions"] if summary["functions"] > 0 else 0

            if avg_complexity > 10:
                recommendations.append("high_complexity: Refactor functions with complexity > 10")
            if summary["max_complexity"] > 15:
                recommendations.append("complex_hotspot: Simplify most complex function")
            if summary["loc"] / summary["files"] > 200:
                recommendations.append("large_files: Split files exceeding 200 LOC")
            if summary["functions"] == 0 and summary["files"] > 2:
                recommendations.append("no_functions: Add function definitions for modularity")
            if summary["classes"] == 0 and summary["files"] > 3:
                recommendations.append("no_classes: Consider OOP structure for organization")

        return {
            "system": "Ecnyss",
            "cycle": analysis["cycle"],
            "metrics": {
                "files": summary["files"],
                "loc": summary["loc"],
                "sloc": summary["sloc"],
                "functions": summary["functions"],
                "classes": summary["classes"],
                "avg_complexity": summary["total_complexity"] / summary["functions"] if summary["functions"] > 0 else 0,
                "max_complexity": summary["max_complexity"]
            },
            "tuning_recommendations": recommendations,
            "target": "/opt/minimax/bin/improver.py"
        }

    def detect_patterns(self) -> List[Dict[str, Any]]:
        """Detect architectural patterns in existing code."""
        analysis = self.analyze_all()
        patterns = []

        files_with_classes = sum(1 for f in analysis["files"] if f["structure"]["classes"])
        files_with_functions = sum(1 for f in analysis["files"] if f["structure"]["functions"])

        if files_with_classes > 0:
            patterns.append({"type": "oop", "strength": files_with_classes / len(analysis["files"])})
        if files_with_functions > files_with_classes:
            patterns.append({"type": "functional", "strength": files_with_functions / len(analysis["files"])})

        import_counts = {}
        for f in analysis["files"]:
            for imp in f["structure"]["imports"]:
                import_counts[imp] = import_counts.get(imp, 0) + 1

        common_imports = {k: v for k, v in import_counts.items() if v > 1}
        if common_imports:
            patterns.append({"type": "dependency_cluster", "modules": list(common_imports.keys())})

        return patterns

    def analyze_all_files(self) -> Dict[str, Any]:
        """Compatibility wrapper used by older runners."""
        return self.analyze_all()

    def analyze(self) -> Dict[str, Any]:
        """Compatibility wrapper used by older runners."""
        return self.analyze_all()


if __name__ == "__main__":
    analyzer = CodeAnalyzer()

    print("=" * 50)
    print("ECNYSS CODE ANALYZER")
    print("=" * 50)

    analysis = analyzer.store_analysis()

    print(f"\nAnalyzed {analysis['summary']['files']} files")
    print(f"Total LOC: {analysis['summary']['loc']}")
    print(f"Total Functions: {analysis['summary']['functions']}")
    print(f"Total Classes: {analysis['summary']['classes']}")

    if analysis['summary']['functions'] > 0:
        avg_comp = analysis['summary']['total_complexity'] / analysis['summary']['functions']
        print(f"Average Complexity: {avg_comp:.2f}")
        print(f"Max Complexity: {analysis['summary']['max_complexity']}")

    print("\n" + "=" * 50)
    print("IMPROVER INPUT")
    print("=" * 50)

    improver_data = analyzer.generate_improver_input()
    print(json.dumps(improver_data, indent=2))

    patterns = analyzer.detect_patterns()
    if patterns:
        print("\n" + "=" * 50)
        print("DETECTED PATTERNS")
        print("=" * 50)
        for p in patterns:
            print(f"  - {p['type']}: {p}")

#!/usr/bin/env python3
"""Performance tracker for Ecnyss - collects execution metrics and pipeline statistics.

Tracks timing, memory usage, and success rates for each pipeline step
to enable data-driven optimization decisions (cycle 37+).
"""
import json
import time
import os
import psutil
from pathlib import Path
from typing import Dict, List, Any, Optional
from datetime import datetime
from contextlib import contextmanager


class PerformanceTracker:
    """Tracks performance metrics for autonomous pipeline execution."""

    def __init__(self, base_path: str = "/root/Ecnyss"):
        self.base_path = Path(base_path)
        self.metrics_file = self.base_path / ".ecnyss_metrics.jsonl"
        self.current_cycle = 0
        self.step_timings = {}
        self.step_memory = {}
        self.step_outcomes = {}
        self.process = psutil.Process()

    def start_cycle(self, cycle: int):
        """Initialize tracking for a new cycle."""
        self.current_cycle = cycle
        self.step_timings = {}
        self.step_memory = {}
        self.step_outcomes = {}
        self._cycle_start_time = time.monotonic()
        self._cycle_start_memory = self.process.memory_info().rss

    @contextmanager
    def track_step(self, step_name: str):
        """Context manager to track a pipeline step's execution."""
        start_time = time.monotonic()
        start_memory = self.process.memory_info().rss

        try:
            yield self
            success = True
            error = None
        except Exception as e:
            success = False
            error = str(e)
            raise
        finally:
            end_time = time.monotonic()
            end_memory = self.process.memory_info().rss

            self.step_timings[step_name] = round(end_time - start_time, 3)
            self.step_memory[step_name] = {
                "delta_mb": round((end_memory - start_memory) / (1024 * 1024), 2),
                "peak_mb": round(end_memory / (1024 * 1024), 2)
            }
            self.step_outcomes[step_name] = {"success": success, "error": error if not success else None}

    def record_step(self, step_name: str, duration_ms: float, success: bool = True, metadata: Optional[Dict] = None):
        """Manually record a step completion."""
        self.step_timings[step_name] = duration_ms
        self.step_outcomes[step_name] = {"success": success, "metadata": metadata or {}}

    def end_cycle(self, overall_success: bool = True) -> Dict[str, Any]:
        """Finalize tracking for current cycle and persist metrics."""
        total_time = round(time.monotonic() - self._cycle_start_time, 3)
        total_memory_delta = round(
            (self.process.memory_info().rss - self._cycle_start_memory) / (1024 * 1024), 2
        )

        metrics = {
            "cycle": self.current_cycle,
            "timestamp": datetime.utcnow().isoformat(),
            "total_time_sec": total_time,
            "memory_delta_mb": total_memory_delta,
            "overall_success": overall_success,
            "steps": {}
        }

        for step in self.step_timings:
            metrics["steps"][step] = {
                "time_sec": self.step_timings[step],
                "memory": self.step_memory.get(step, {}),
                "outcome": self.step_outcomes.get(step, {"success": True})
            }

        # Persist to metrics log
        with open(self.metrics_file, 'a') as f:
            f.write(json.dumps(metrics) + '\n')

        return metrics

    def get_cycle_stats(self, cycles: int = 10) -> Dict[str, Any]:
        """Analyze recent cycle performance statistics."""
        if not self.metrics_file.exists():
            return {"status": "no_data"}

        recent_metrics = []
        with open(self.metrics_file, 'r') as f:
            for line in f:
                try:
                    entry = json.loads(line.strip())
                    recent_metrics.append(entry)
                except json.JSONDecodeError:
                    continue

        # Take last N cycles
        recent_metrics = recent_metrics[-cycles:]

        if not recent_metrics:
            return {"status": "no_data"}

        # Calculate aggregates
        total_times = [m["total_time_sec"] for m in recent_metrics]
        success_count = sum(1 for m in recent_metrics if m["overall_success"])

        # Per-step aggregates
        step_stats = {}
        for metric in recent_metrics:
            for step_name, step_data in metric.get("steps", {}).items():
                if step_name not in step_stats:
                    step_stats[step_name] = {"times": [], "successes": 0, "failures": 0}
                step_stats[step_name]["times"].append(step_data["time_sec"])
                if step_data.get("outcome", {}).get("success", True):
                    step_stats[step_name]["successes"] += 1
                else:
                    step_stats[step_name]["failures"] += 1

        # Compute averages
        for step_name, stats in step_stats.items():
            times = stats["times"]
            stats["avg_time_sec"] = round(sum(times) / len(times), 3) if times else 0
            stats["max_time_sec"] = round(max(times), 3) if times else 0
            stats["min_time_sec"] = round(min(times), 3) if times else 0
            stats["total_executions"] = len(times)
            del stats["times"]  # Remove raw data

        return {
            "cycles_analyzed": len(recent_metrics),
            "success_rate": round(success_count / len(recent_metrics), 2),
            "avg_cycle_time_sec": round(sum(total_times) / len(total_times), 2),
            "max_cycle_time_sec": round(max(total_times), 2),
            "step_breakdown": step_stats,
            "slowest_step": max(step_stats.items(), key=lambda x: x[1]["avg_time_sec"])[0] if step_stats else None
        }

    def identify_bottlenecks(self, threshold_sec: float = 5.0) -> List[Dict[str, Any]]:
        """Identify pipeline steps that consistently exceed threshold."""
        stats = self.get_cycle_stats(cycles=20)

        if stats.get("status") == "no_data":
            return []

        bottlenecks = []
        for step_name, step_stats in stats.get("step_breakdown", {}).items():
            if step_stats["avg_time_sec"] > threshold_sec:
                bottlenecks.append({
                    "step": step_name,
                    "avg_time_sec": step_stats["avg_time_sec"],
                    "max_time_sec": step_stats["max_time_sec"],
                    "executions": step_stats["total_executions"]
                })

        return sorted(bottlenecks, key=lambda x: x["avg_time_sec"], reverse=True)

    def get_recommendations(self) -> List[str]:
        """Generate optimization recommendations based on metrics."""
        recommendations = []
        stats = self.get_cycle_stats(cycles=10)

        if stats.get("status") == "no_data":
            return ["Insufficient data for recommendations"]

        # Check success rate
        if stats["success_rate"] < 0.9:
            recommendations.append(
                f"Low success rate detected ({stats['success_rate']:.0%}). "
                "Consider adding more validation or recovery steps."
            )

        # Check for slow cycles
        if stats["avg_cycle_time_sec"] > 60:
            recommendations.append(
                f"Cycles are slow (avg {stats['avg_cycle_time_sec']}s). "
                f"Review '{stats['slowest_step']}' step for optimization."
            )

        # Check specific bottlenecks
        bottlenecks = self.identify_bottlenecks(threshold_sec=10.0)
        for bottleneck in bottlenecks[:3]:
            recommendations.append(
                f"Step '{bottleneck['step']}' is slow (avg {bottleneck['avg_time_sec']}s, "
                f"max {bottleneck['max_time_sec']}s). Consider caching or parallelization."
            )

        return recommendations if recommendations else ["No significant issues detected"]

    def record_cycle(self, cycle: int, duration: float, analysis: Dict[str, Any]) -> None:
        """Compatibility wrapper used by older runners."""
        entry = {
            "cycle": cycle,
            "timestamp": datetime.utcnow().isoformat(),
            "total_time_sec": round(float(duration), 3),
            "memory_delta_mb": 0.0,
            "overall_success": bool(analysis.get("success", False)),
            "steps": {
                "legacy_cycle_record": {
                    "time_sec": round(float(duration), 3),
                    "memory": {},
                    "outcome": {"success": bool(analysis.get("success", False)), "error": None},
                }
            },
        }
        with open(self.metrics_file, 'a') as f:
            f.write(json.dumps(entry) + '\n')


if __name__ == "__main__":
    tracker = PerformanceTracker()

    # Simulate tracking
    tracker.start_cycle(37)

    with tracker.track_step("health_check"):
        time.sleep(0.1)

    with tracker.track_step("dependency_analysis"):
        time.sleep(0.2)

    metrics = tracker.end_cycle(overall_success=True)
    print(f"Cycle metrics: {json.dumps(metrics, indent=2)}")

    print("\nRecent stats:", json.dumps(tracker.get_cycle_stats(), indent=2))
    print("\nRecommendations:", tracker.get_recommendations())

#!/usr/bin/env python3
"""Evolution executor for Ecnyss - executes validated evolution plans.

Performs actual file operations based on decision engine outputs.
Completes the self-modification loop for autonomous operation (cycles 16+).
"""
import json
import os
import shutil
import subprocess
from pathlib import Path
from typing import Dict, List, Any, Optional, Tuple
from datetime import datetime

# Import existing infrastructure
from output_validator import OutputValidator
from state_tracker import StateTracker
from semantic_validator import SemanticValidator

class EvolutionExecutor:
    """Executes evolution plans safely with validation and rollback."""

    def __init__(self, base_path: str = "/root/Ecnyss"):
        self.base_path = Path(base_path)
        self.validator = OutputValidator()
        self.semantic_validator = SemanticValidator()
        self.tracker = StateTracker(base_path)
        self.backup_dir = self.base_path / ".ecnyss_backups"
        self.backup_dir.mkdir(exist_ok=True)

    def execute_plan(self, plan: Dict[str, Any], cycle: int) -> Tuple[bool, List[str]]:
        """Execute an evolution plan with full validation and rollback on failure."""
        # Validate plan structure first
        valid, errors = self.validator.validate_plan_structure(plan)
        if not valid:
            return False, [f"Validation failed: {e}" for e in errors]

        # Validate semantic quality of file contents (cycle 43)
        files = plan.get('files', [])
        for file_entry in files:
            path = file_entry.get('path')
            content = file_entry.get('content')
            if content and path:
                sem_valid, sem_errors = self.semantic_validator.validate_content(content, path)
                if not sem_valid:
                    return False, [f"Semantic validation failed for {path}: {e}" for e in sem_errors]

        executed_files = []
        backup_paths = {}

        try:
            action = plan.get('action')

            for file_entry in files:
                path = file_entry.get('path')
                content = file_entry.get('content')

                if not path:
                    continue

                full_path = self.base_path / path

                # Backup existing file if modifying
                if action in ['modify', 'refactor'] and full_path.exists():
                    backup_path = self.backup_dir / f"{path}.{cycle}.bak"
                    backup_path.parent.mkdir(parents=True, exist_ok=True)
                    shutil.copy2(full_path, backup_path)
                    backup_paths[path] = backup_path

                # Execute based on action
                if action == 'create':
                    if full_path.exists():
                        return False, [f"File already exists: {path}"]
                    full_path.parent.mkdir(parents=True, exist_ok=True)
                    full_path.write_text(content)
                    executed_files.append(path)

                elif action == 'modify' or action == 'refactor':
                    full_path.parent.mkdir(parents=True, exist_ok=True)
                    full_path.write_text(content)
                    executed_files.append(path)

                elif action == 'delete':
                    if full_path.exists():
                        backup_path = self.backup_dir / f"{path}.{cycle}.bak"
                        shutil.copy2(full_path, backup_path)
                        backup_paths[path] = backup_path
                        full_path.unlink()
                        executed_files.append(path)

            # Record successful execution
            for filepath in executed_files:
                self.tracker.record_file_creation(filepath, cycle)

            # Commit + push successful code changes if git is available.
            git_result = self._git_record(cycle, plan, executed_files)

            # Log execution to evolution
            self._log_execution(plan, cycle, True, None, git_result)

            return True, executed_files

        except Exception as e:
            # Rollback on failure
            self._rollback(backup_paths)
            self._log_execution(plan, cycle, False, str(e), None)
            return False, [f"Execution failed: {str(e)}"]

    def _git_record(self, cycle: int, plan: Dict[str, Any], files_affected: List[str]) -> Dict[str, Any]:
        """Record successful changes in git and optionally push."""
        repo = self.base_path
        if not (repo / ".git").exists():
            return {"committed": False, "pushed": False, "reason": "no_git_repo"}

        if os.environ.get("ECNYSS_GIT_COMMIT", "1").lower() in {"0", "false", "no"}:
            return {"committed": False, "pushed": False, "reason": "commit_disabled"}

        def _run(args: List[str], timeout: int = 20) -> subprocess.CompletedProcess:
            return subprocess.run(
                ["git", "-C", str(repo), *args],
                capture_output=True,
                text=True,
                timeout=timeout
            )

        # Stage only files touched by this plan to avoid scooping unrelated edits.
        unique_files: List[str] = []
        for path in files_affected:
            if not path:
                continue
            rel_path = str(Path(path))
            if rel_path not in unique_files:
                unique_files.append(rel_path)
        if not unique_files:
            return {"committed": False, "pushed": False, "reason": "no_files_affected"}

        pre_staged = _run(["diff", "--cached", "--name-only"])
        if pre_staged.returncode == 0 and pre_staged.stdout.strip():
            return {"committed": False, "pushed": False, "reason": "preexisting_staged_changes"}

        add_errors: List[str] = []
        for rel_path in unique_files:
            add = _run(["add", "-A", "--", rel_path])
            if add.returncode != 0:
                add_errors.append(f"{rel_path}: {add.stderr.strip()[:120]}")

        diff = _run(["diff", "--cached", "--quiet"])
        if diff.returncode == 0:
            reason = "no_staged_changes"
            if add_errors:
                reason = f"git_add_warnings: {'; '.join(add_errors)[:180]}"
            return {"committed": False, "pushed": False, "reason": reason}

        summary_source = plan.get("summary") or plan.get("reasoning") or "autonomous update"
        summary = " ".join(str(summary_source).split())[:72]
        action = str(plan.get("action") or "update")
        message = f"ecnyss cycle {cycle}: {action} - {summary}"

        commit = _run(["commit", "-m", message], timeout=30)
        if commit.returncode != 0:
            return {
                "committed": False,
                "pushed": False,
                "reason": f"git_commit_failed: {commit.stderr.strip()[:180]}",
            }

        pushed = False
        push_reason = "push_disabled"
        if os.environ.get("ECNYSS_GIT_PUSH", "1").lower() not in {"0", "false", "no"}:
            branch = _run(["rev-parse", "--abbrev-ref", "HEAD"])
            if branch.returncode == 0:
                branch_name = branch.stdout.strip() or "main"
                remote_name = os.environ.get("ECNYSS_GIT_REMOTE", "origin")
                push = _run(["push", remote_name, branch_name], timeout=60)
                if push.returncode == 0:
                    pushed = True
                    push_reason = "ok"
                else:
                    push_reason = f"git_push_failed: {push.stderr.strip()[:180]}"
            else:
                push_reason = "branch_unknown"

        return {"committed": True, "pushed": pushed, "reason": push_reason}

    def execute(self, decision: Dict[str, Any], _context: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
        """Compatibility wrapper used by older runners."""
        cycle = int(decision.get("cycle") or (self.tracker.get_current_cycle() + 1))
        success, result = self.execute_plan(decision, cycle)
        return {
            "success": success,
            "files_modified": len(result) if success else 0,
            "files": result if success else [],
            "error": None if success else "; ".join(result),
        }

    def _rollback(self, backup_paths: Dict[str, Path]):
        """Restore files from backups on failure."""
        for path, backup in backup_paths.items():
            full_path = self.base_path / path
            if backup.exists():
                full_path.parent.mkdir(parents=True, exist_ok=True)
                shutil.copy2(backup, full_path)

    def _log_execution(
        self,
        plan: Dict,
        cycle: int,
        success: bool,
        error: Optional[str],
        git_result: Optional[Dict[str, Any]] = None
    ):
        """Log execution result to evolution.jsonl."""
        entry = {
            "status": "ok" if success else "failed",
            "action": plan.get('action'),
            "files": [f.get('path') for f in plan.get('files', [])],
            "cycle": cycle,
            "timestamp": datetime.utcnow().isoformat(),
            "model": "evolution_executor",
            "error": error
        }
        if git_result is not None:
            entry["git"] = git_result

        with open(self.base_path / "evolution.jsonl", 'a') as f:
            f.write(json.dumps(entry) + '\n')

    def get_execution_history(self, limit: int = 10) -> List[Dict]:
        """Get recent execution history from evolution log."""
        from self_reader import EcnyssReader
        reader = EcnyssReader(self.base_path)
        entries = reader.read_evolution_log()
        return [e for e in entries if e.get('model') == 'evolution_executor'][-limit:]

if __name__ == "__main__":
    executor = EvolutionExecutor()

    # Test with a sample plan
    test_plan = {
        "action": "create",
        "files": [{"path": "test_output.txt", "content": "# Test file created by executor\n"}],
        "summary": "Test execution",
        "reasoning": "Testing the executor before cycle 16 autonomous operation"
    }

    success, result = executor.execute_plan(test_plan, 15)
    print(f"Execution success: {success}")
    print(f"Result: {result}")

#!/usr/bin/env python3
"""State tracker for Ecnyss - tracks system state across cycles.

Provides persistent state storage for mid-cycle memory requirements.
"""
import json
import os
import subprocess
from datetime import datetime
from pathlib import Path
from typing import Dict, Any, Optional, List

class StateTracker:
    def __init__(self, base_path: str = "/root/Ecnyss"):
        self.base_path = Path(base_path)
        self.state_file = self.base_path / ".ecnyss_state.json"
        self._state = self._load_state()

    def _load_state(self) -> Dict[str, Any]:
        """Load state from disk or initialize."""
        if self.state_file.exists():
            with open(self.state_file, 'r') as f:
                return json.load(f)
        return {
            "initialized": True,
            "first_cycle": 10,
            "files_created": [],
            "patterns_learned": {}
        }

    def load_state(self) -> Dict[str, Any]:
        """Compatibility wrapper used by older runners."""
        return dict(self._state)

    def save_state(self):
        """Persist state to disk."""
        with open(self.state_file, 'w') as f:
            json.dump(self._state, f, indent=2)

    def get_git_status(self) -> Dict[str, Any]:
        """Get current git status."""
        try:
            result = subprocess.run(
                ["git", "status", "--porcelain"],
                cwd=self.base_path,
                capture_output=True,
                text=True
            )
            return {
                "clean": result.returncode == 0 and not result.stdout.strip(),
                "output": result.stdout if result.stdout else None
            }
        except Exception as e:
            return {"clean": False, "error": str(e)}

    def get_current_cycle(self) -> int:
        """Determine current cycle from git log or state."""
        try:
            result = subprocess.run(
                ["git", "log", "--oneline"],
                cwd=self.base_path,
                capture_output=True,
                text=True
            )
            lines = [l for l in result.stdout.split('\n') if l.strip()]
            # Look for cycle markers in commit messages
            for line in lines:
                if 'cycle #' in line.lower():
                    import re
                    match = re.search(r'cycle #(\d+)', line.lower())
                    if match:
                        return int(match.group(1))
            return len(lines)  # Fallback to commit count
        except Exception:
            return self._state.get("last_known_cycle", 0)

    def record_file_creation(self, filename: str, cycle: int):
        """Record that a file was created in a cycle."""
        self._state.setdefault("files_created", []).append({
            "file": filename,
            "cycle": cycle,
            "timestamp": datetime.utcnow().isoformat()
        })
        self.save_state()

    def get_system_summary(self) -> Dict[str, Any]:
        """Get complete system state summary."""
        return {
            "current_cycle": self.get_current_cycle(),
            "base_path": str(self.base_path),
            "files_tracked": self._state.get("files_created", []),
            "git_status": self.get_git_status(),
            "timestamp": datetime.utcnow().isoformat()
        }

    def capture_state(self, context_files: Optional[List[Dict[str, Any]]] = None) -> Dict[str, Any]:
        """Compatibility wrapper used by older runners."""
        summary = self.get_system_summary()
        summary["context_files"] = context_files or []
        return summary

if __name__ == "__main__":
    tracker = StateTracker()
    summary = tracker.get_system_summary()
    print(json.dumps(summary, indent=2))

#!/usr/bin/env python3
"""Output validator for Ecnyss - prevents JSON parsing failures.

Validates that code outputs meet the strict JSON-only requirement.
This addresses the root cause of cycles 6-8 failures (json_failed).
"""
import json
import re
from typing import Tuple, Optional, List

class OutputValidator:
    """Validates Ecnyss outputs meet strict formatting requirements."""

    MAX_FILES = 3
    ALLOWED_ACTIONS = ["create", "modify", "delete", "refactor"]

    @staticmethod
    def validate_json_only(text: str) -> Tuple[bool, Optional[str]]:
        """Check if text is valid JSON with no extra content."""
        text = text.strip()

        # Check for markdown code blocks (common error)
        if text.startswith('') or text.endswith(''):
            return False, "Contains markdown code blocks"

        # Check for explanatory text before/after JSON
        lines = text.split('\n')
        if len(lines) > 1:
            # Multi-line should be valid JSON object
            try:
                json.loads(text)
                return True, None
            except json.JSONDecodeError as e:
                return False, f"Invalid JSON: {e}"

        # Single line must be valid JSON
        try:
            json.loads(text)
            return True, None
        except json.JSONDecodeError as e:
            return False, f"Invalid JSON: {e}"

    @staticmethod
    def validate_plan_structure(plan: dict) -> Tuple[bool, List[str]]:
        """Validate the structure of an evolution plan."""
        errors = []

        # Required fields
        if 'action' not in plan:
            errors.append("Missing 'action' field")
        elif plan['action'] not in OutputValidator.ALLOWED_ACTIONS:
            errors.append(f"Invalid action: {plan['action']}")

        if 'files' not in plan:
            errors.append("Missing 'files' field")
        elif not isinstance(plan['files'], list):
            errors.append("'files' must be a list")
        elif len(plan['files']) > OutputValidator.MAX_FILES:
            errors.append(f"Too many files: {len(plan['files'])} > {OutputValidator.MAX_FILES}")

        if 'summary' not in plan:
            errors.append("Missing 'summary' field")

        if 'reasoning' not in plan:
            errors.append("Missing 'reasoning' field")

        # Validate file entries
        for i, file_entry in enumerate(plan.get('files', [])):
            if not isinstance(file_entry, dict):
                errors.append(f"File entry {i} is not an object")
                continue
            if 'path' not in file_entry:
                errors.append(f"File entry {i} missing 'path'")
            if 'content' not in file_entry:
                errors.append(f"File entry {i} missing 'content'")

        return len(errors) == 0, errors

    @staticmethod
    def sanitize_output(text: str) -> str:
        """Attempt to extract JSON from text with extra content."""
        # Look for JSON object pattern
        text = text.strip()

        # Remove common prefixes
        prefixes = [
            r'^\s*',
            r'^\s*',
            r'^[^{]*',
        ]

        for prefix in prefixes:
            text = re.sub(prefix, '', text, flags=re.MULTILINE)

        # Remove common suffixes  
        suffixes = [
            r'\s*$',
            r'[^}]*$',
        ]

        for suffix in suffixes:
            text = re.sub(suffix, '', text, flags=re.MULTILINE)

        return text.strip()

    def validate(self, execution_result) -> bool:
        """Compatibility wrapper used by older runners."""
        if isinstance(execution_result, dict):
            return bool(execution_result.get("success", False))
        return False

if __name__ == "__main__":
    # Test validation
    validator = OutputValidator()

    # Test valid JSON
    valid = '{"action": "create", "files": [], "summary": "test", "reasoning": "test"}'
    ok, err = validator.validate_json_only(valid)
    print(f"Valid JSON test: {ok} (error: {err})")

    # Test invalid (markdown wrapped)
    invalid = "\n{\"action\": \"create\"}\n"
    ok, err = validator.validate_json_only(invalid)
    print(f"Invalid JSON test: {ok} (error: {err})")

    # Test structure validation
    plan = {
        "action": "create",
        "files": [{"path": "test.py", "content": "# test"}],
        "summary": "Test file",
        "reasoning": "Testing validator"
    }
    ok, errors = validator.validate_plan_structure(plan)
    print(f"Structure validation: {ok} (errors: {errors})")

#!/usr/bin/env python3
"""Health monitor for Ecnyss - system integrity and health checking.

Validates system state, detects corruption, and reports health metrics.
Integrates with autonomous_orchestrator to prevent evolution of broken states.
"""
import ast
import json
from pathlib import Path
from typing import Dict, List, Any, Optional, Tuple
from datetime import datetime

from self_reader import EcnyssReader

class HealthMonitor:
    """Monitors Ecnyss system health and integrity."""

    def __init__(self, base_path: str = "/root/Ecnyss"):
        self.base_path = Path(base_path)
        self.reader = EcnyssReader(base_path)
        self.health_log = self.base_path / "health.jsonl"

    def check_python_syntax(self, file_path: Path) -> Tuple[bool, Optional[str]]:
        """Check if a Python file has valid syntax."""
        try:
            content = file_path.read_text()
            ast.parse(content)
            return True, None
        except SyntaxError as e:
            return False, f"Syntax error: {e}"
        except Exception as e:
            return False, str(e)

    def check_all_files(self) -> Dict[str, Any]:
        """Check all Python files for syntax errors."""
        results = {
            "timestamp": datetime.utcnow().isoformat(),
            "total_files": 0,
            "valid_files": 0,
            "invalid_files": [],
            "missing_critical": []
        }

        py_files = self.reader.list_python_files()
        results["total_files"] = len(py_files)

        critical_files = [
            "self_reader.py",
            "state_tracker.py", 
            "output_validator.py",
            "code_analyzer.py",
            "cycle_optimizer.py",
            "decision_engine.py",
            "evolution_executor.py",
            "autonomous_orchestrator.py"
        ]

        for rel_path in py_files:
            full_path = self.base_path / rel_path
            valid, error = self.check_python_syntax(full_path)

            if valid:
                results["valid_files"] += 1
            else:
                results["invalid_files"].append({
                    "path": rel_path,
                    "error": error
                })

        for critical in critical_files:
            if not (self.base_path / critical).exists():
                results["missing_critical"].append(critical)

        return results

    def check_evolution_health(self, window: int = 5) -> Dict[str, Any]:
        """Check recent evolution health."""
        entries = self.reader.read_evolution_log()
        recent = entries[-window:] if len(entries) >= window else entries

        failures = [e for e in recent if self._is_failure_status(e.get('status'))]

        return {
            "recent_cycles": len(recent),
            "failures": len(failures),
            "failure_rate": len(failures) / len(recent) if recent else 0,
            "last_failure": failures[-1] if failures else None,
            "consecutive_failures": self._count_consecutive_failures(entries)
        }

    def _count_consecutive_failures(self, entries: List[Dict]) -> int:
        """Count consecutive failures at the end of the log."""
        count = 0
        for entry in reversed(entries):
            if self._is_failure_status(entry.get('status')):
                count += 1
            else:
                break
        return count

    def _is_failure_status(self, status: Any) -> bool:
        """Return True only for real failure statuses."""
        status_str = str(status or "").strip().lower()
        return status_str in {"failed", "error", "crashed"}

    def generate_health_report(self) -> Dict[str, Any]:
        """Generate comprehensive health report."""
        file_health = self.check_all_files()
        evolution_health = self.check_evolution_health()

        report = {
            "timestamp": datetime.utcnow().isoformat(),
            "cycle": self._get_current_cycle(),
            "file_health": file_health,
            "evolution_health": evolution_health,
            "overall_status": "healthy" if self._is_healthy(file_health, evolution_health) else "degraded"
        }

        self._log_health(report)
        return report

    def _get_current_cycle(self) -> int:
        """Get current cycle from evolution log."""
        entries = self.reader.read_evolution_log()
        if entries:
            return max(e.get('cycle', 0) for e in entries)
        return 0

    def _is_healthy(self, file_health: Dict, evolution_health: Dict) -> bool:
        """Determine if system is healthy."""
        if file_health.get("invalid_files"):
            return False
        if file_health.get("missing_critical"):
            return False
        if evolution_health.get("consecutive_failures", 0) >= 2:
            return False
        if evolution_health.get("failure_rate", 0) > 0.5:
            return False
        return True

    def _log_health(self, report: Dict):
        """Log health report to health.jsonl."""
        with open(self.health_log, 'a') as f:
            f.write(json.dumps(report) + '\n')

    def get_health_history(self, limit: int = 10) -> List[Dict]:
        """Get recent health reports."""
        if not self.health_log.exists():
            return []

        entries = []
        with open(self.health_log, 'r') as f:
            for line in f:
                line = line.strip()
                if line:
                    try:
                        entries.append(json.loads(line))
                    except json.JSONDecodeError:
                        continue
        return entries[-limit:]

    def is_system_healthy(self) -> bool:
        """Quick check for orchestrator integration."""
        report = self.generate_health_report()
        return report["overall_status"] == "healthy"

    def check(self) -> Dict[str, Any]:
        """Compatibility wrapper used by older runners."""
        report = self.generate_health_report()
        return {
            "healthy": report.get("overall_status") == "healthy",
            "overall_status": report.get("overall_status"),
            "file_health": report.get("file_health", {}),
            "evolution_health": report.get("evolution_health", {}),
        }

if __name__ == "__main__":
    monitor = HealthMonitor()
    report = monitor.generate_health_report()
    print(json.dumps(report, indent=2))

    if report["overall_status"] != "healthy":
        print("\nWARNING: System health is degraded!")
        if report["file_health"]["invalid_files"]:
            print("Invalid files detected:")
            for f in report["file_health"]["invalid_files"]:
                print(f"  - {f['path']}: {f['error']}")

#!/usr/bin/env python3
"""Test runner for Ecnyss - validates functionality of system components.

Executes tests on system modules to verify they work correctly before
marking cycles as successful. Prevents broken code from persisting (cycle 24).
"""
import importlib
import sys
import traceback
from pathlib import Path
from typing import Dict, List, Any, Optional
from datetime import datetime
import json

class TestRunner:
    """Runs functional tests on Ecnyss components."""

    def __init__(self, base_path: str = "/root/Ecnyss"):
        self.base_path = Path(base_path)
        self.test_results = []

    def test_imports(self) -> Dict[str, Any]:
        """Test that all modules can be imported without errors."""
        modules = [
            "self_reader",
            "state_tracker", 
            "output_validator",
            "code_analyzer",
            "cycle_optimizer",
            "decision_engine",
            "evolution_executor",
            "autonomous_orchestrator",
            "health_monitor",
            "recovery_engine",
            "cycle_driver",
        ]

        results = {
            "timestamp": datetime.utcnow().isoformat(),
            "total": len(modules),
            "passed": 0,
            "failed": [],
            "details": {}
        }

        for mod_name in modules:
            try:
                # Add base path to sys.path temporarily
                if str(self.base_path) not in sys.path:
                    sys.path.insert(0, str(self.base_path))

                module = importlib.import_module(mod_name)
                results["passed"] += 1
                results["details"][mod_name] = {"status": "ok", "error": None}
            except Exception as e:
                results["failed"].append({
                    "module": mod_name,
                    "error": str(e),
                    "traceback": traceback.format_exc()
                })
                results["details"][mod_name] = {"status": "failed", "error": str(e)}

        return results

    def test_functionality(self) -> Dict[str, Any]:
        """Test basic functionality of key components."""
        tests = []

        # Test self_reader
        try:
            from self_reader import EcnyssReader
            reader = EcnyssReader(self.base_path)
            files = reader.list_python_files()
            tests.append({
                "name": "self_reader.list_python_files",
                "status": "ok" if len(files) > 0 else "failed",
                "details": f"Found {len(files)} files"
            })
        except Exception as e:
            tests.append({
                "name": "self_reader",
                "status": "failed",
                "error": str(e)
            })

        # Test state_tracker
        try:
            from state_tracker import StateTracker
            tracker = StateTracker(self.base_path)
            state = tracker.load_state()
            tests.append({
                "name": "state_tracker.load_state",
                "status": "ok",
                "details": f"State has {len(state.get('files', []))} files"
            })
        except Exception as e:
            tests.append({
                "name": "state_tracker",
                "status": "failed",
                "error": str(e)
            })

        # Test output_validator
        try:
            from output_validator import OutputValidator
            validator = OutputValidator()
            plan = {
                "action": "create",
                "files": [{"path": "test.py", "content": "# test"}],
                "summary": "Test",
                "reasoning": "Testing"
            }
            valid, errors = validator.validate_plan_structure(plan)
            tests.append({
                "name": "output_validator.validate_plan_structure",
                "status": "ok" if valid else "failed",
                "details": f"Valid: {valid}"
            })
        except Exception as e:
            tests.append({
                "name": "output_validator",
                "status": "failed",
                "error": str(e)
            })

        # Test health_monitor
        try:
            from health_monitor import HealthMonitor
            monitor = HealthMonitor(self.base_path)
            healthy = monitor.is_system_healthy()
            tests.append({
                "name": "health_monitor.is_system_healthy",
                "status": "ok",
                "details": f"Healthy: {healthy}"
            })
        except Exception as e:
            tests.append({
                "name": "health_monitor",
                "status": "failed",
                "error": str(e)
            })

        passed = sum(1 for t in tests if t["status"] == "ok")
        return {
            "timestamp": datetime.utcnow().isoformat(),
            "total": len(tests),
            "passed": passed,
            "failed": len(tests) - passed,
            "tests": tests
        }

    def run_all_tests(self) -> Dict[str, Any]:
        """Run complete test suite."""
        import_tests = self.test_imports()
        func_tests = self.test_functionality()

        all_passed = (
            import_tests["failed"] == [] and 
            func_tests["failed"] == 0
        )

        report = {
            "timestamp": datetime.utcnow().isoformat(),
            "overall_status": "passed" if all_passed else "failed",
            "import_tests": import_tests,
            "functionality_tests": func_tests,
            "summary": {
                "modules_ok": import_tests["passed"],
                "modules_failed": len(import_tests["failed"]),
                "functions_ok": func_tests["passed"],
                "functions_failed": func_tests["failed"]
            }
        }

        self._log_results(report)
        return report

    def _log_results(self, report: Dict):
        """Log test results to test_results.jsonl."""
        log_path = self.base_path / "test_results.jsonl"
        with open(log_path, 'a') as f:
            f.write(json.dumps(report) + '\n')

    def is_system_functional(self) -> bool:
        """Quick check for integration into cycle pipeline."""
        report = self.run_all_tests()
        return report["overall_status"] == "passed"

    def run(self) -> Dict[str, Any]:
        """Compatibility wrapper used by older runners."""
        report = self.run_all_tests()
        summary = report.get("summary", {})
        return {
            "passed": int(summary.get("functions_ok", 0)) + int(summary.get("modules_ok", 0)),
            "failed": int(summary.get("functions_failed", 0)) + int(summary.get("modules_failed", 0)),
            "overall_status": report.get("overall_status"),
        }

if __name__ == "__main__":
    runner = TestRunner()
    report = runner.run_all_tests()

    print(json.dumps(report["summary"], indent=2))

    if report["overall_status"] != "passed":
        print("\nFAILED TESTS:")
        for mod in report["import_tests"].get("failed", []):
            print(f"  - {mod['module']}: {mod['error']}")
        for test in report["functionality_tests"].get("tests", []):
            if test["status"] != "ok":
                print(f"  - {test['name']}: {test.get('error', 'Unknown error')}")
        sys.exit(1)
    else:
        print("\nAll tests passed!")
        sys.exit(0)

#!/usr/bin/env python3
"""Cycle optimizer for Ecnyss - analyzes performance data and generates optimization recommendations.

Uses metrics collected by performance_tracker to identify bottlenecks,
analyze trends, and suggest concrete improvements for pipeline efficiency.
Completes the feedback loop from measurement to optimization (cycle 40+).
"""
import json
import statistics
from pathlib import Path
from typing import Dict, List, Any, Optional, Tuple
from datetime import datetime, timedelta


class CycleOptimizer:
    """Analyzes performance metrics and generates optimization recommendations."""

    def __init__(self, base_path: str = "/root/Ecnyss"):
        self.base_path = Path(base_path)
        self.metrics_dir = self.base_path / ".ecnyss_metrics"
        self.metrics_file = self.metrics_dir / "performance_log.jsonl"
        self.recommendations_file = self.metrics_dir / "optimization_recommendations.json"
        self.thresholds = {
            "slow_step_ms": 5000,
            "memory_leak_mb": 20,
            "high_failure_rate": 0.1,
            "trend_cycles": 5
        }

    def analyze_performance(self, cycle: int) -> Dict[str, Any]:
        """Analyze recent performance data and identify optimization opportunities."""
        if not self.metrics_file.exists():
            return {"status": "no_data", "recommendations": [], "cycle": cycle}

        metrics = self._load_metrics()
        if not metrics:
            return {"status": "no_valid_data", "recommendations": [], "cycle": cycle}

        recent = metrics[-self.thresholds["trend_cycles"]:]

        step_analysis = self._analyze_steps(recent)
        trend_analysis = self._analyze_trends(metrics)
        bottleneck_analysis = self._identify_bottlenecks(recent)

        recommendations = []
        recommendations.extend(self._generate_step_recommendations(step_analysis))
        recommendations.extend(self._generate_trend_recommendations(trend_analysis))
        recommendations.extend(self._generate_bottleneck_recommendations(bottleneck_analysis))

        recommendations.sort(key=lambda x: x.get("severity_score", 0), reverse=True)

        result = {
            "status": "analyzed",
            "cycle": cycle,
            "cycles_analyzed": len(recent),
            "total_cycles": len(metrics),
            "recommendations": recommendations[:10],
            "summary": {
                "total_steps_analyzed": len(step_analysis),
                "degrading_trends": len([t for t in trend_analysis if t["trend"] == "degrading"]),
                "critical_bottlenecks": len([b for b in bottleneck_analysis if b["severity"] == "critical"]),
                "estimated_time_saved_ms": sum(r.get("potential_savings_ms", 0) for r in recommendations)
            },
            "timestamp": datetime.utcnow().isoformat()
        }

        self._save_recommendations(result)

        return result

    def _load_metrics(self) -> List[Dict]:
        """Load all metrics from the log file."""
        metrics = []
        if not self.metrics_file.exists():
            return metrics

        with open(self.metrics_file, 'r') as f:
            for line in f:
                line = line.strip()
                if not line:
                    continue
                try:
                    entry = json.loads(line)
                    metrics.append(entry)
                except json.JSONDecodeError:
                    continue
        return metrics

    def _analyze_steps(self, metrics: List[Dict]) -> Dict[str, Dict]:
        """Analyze performance by pipeline step."""
        step_data = {}

        for entry in metrics:
            for step in entry.get('steps', []):
                step_name = step.get('step', 'unknown')
                if step_name not in step_data:
                    step_data[step_name] = {
                        'durations': [],
                        'memory_deltas': [],
                        'successes': [],
                        'timestamps': []
                    }

                step_data[step_name]['durations'].append(step.get('duration_ms', 0))
                step_data[step_name]['memory_deltas'].append(step.get('memory_delta_mb', 0))
                step_data[step_name]['successes'].append(step.get('success', True))
                step_data[step_name]['timestamps'].append(entry.get('timestamp', ''))

        analysis = {}
        for step_name, data in step_data.items():
            durations = data['durations']
            memory_deltas = data['memory_deltas']
            successes = data['successes']

            analysis[step_name] = {
                'avg_duration_ms': statistics.mean(durations) if durations else 0,
                'max_duration_ms': max(durations) if durations else 0,
                'std_duration': statistics.stdev(durations) if len(durations) > 1 else 0,
                'avg_memory_delta_mb': statistics.mean(memory_deltas) if memory_deltas else 0,
                'max_memory_delta_mb': max(memory_deltas) if memory_deltas else 0,
                'failure_rate': 1 - (sum(successes) / len(successes)) if successes else 0,
                'sample_size': len(durations)
            }

        return analysis

    def _analyze_trends(self, metrics: List[Dict]) -> List[Dict]:
        """Identify degrading performance trends over time."""
        if len(metrics) < 3:
            return []

        trends = []

        step_timeline = {}
        for entry in metrics:
            cycle = entry.get('cycle', 0)
            for step in entry.get('steps', []):
                step_name = step.get('step', 'unknown')
                if step_name not in step_timeline:
                    step_timeline[step_name] = []
                step_timeline[step_name].append({
                    'cycle': cycle,
                    'duration': step.get('duration_ms', 0),
                    'memory': step.get('memory_delta_mb', 0),
                    'success': step.get('success', True)
                })

        for step_name, timeline in step_timeline.items():
            if len(timeline) < 3:
                continue

            durations = [t['duration'] for t in timeline]
            first_half_avg = statistics.mean(durations[:len(durations)//2])
            second_half_avg = statistics.mean(durations[len(durations)//2:])

            if second_half_avg > first_half_avg * 1.2:
                trends.append({
                    "step": step_name,
                    "trend": "degrading",
                    "metric": "duration",
                    "increase_percent": ((second_half_avg - first_half_avg) / first_half_avg) * 100,
                    "severity": "high" if second_half_avg > first_half_avg * 1.5 else "medium"
                })

            memories = [t['memory'] for t in timeline]
            if all(m > 0 for m in memories[-3:]):
                trends.append({
                    "step": step_name,
                    "trend": "degrading",
                    "metric": "memory",
                    "recent_avg_mb": statistics.mean(memories[-3:]),
                    "severity": "high" if statistics.mean(memories[-3:]) > 50 else "medium"
                })

        return trends

    def _identify_bottlenecks(self, metrics: List[Dict]) -> List[Dict]:
        """Identify the slowest and most resource-intensive steps."""
        if not metrics:
            return []

        step_totals = {}
        for entry in metrics:
            for step in entry.get('steps', []):
                step_name = step.get('step', 'unknown')
                if step_name not in step_totals:
                    step_totals[step_name] = {'total_time': 0, 'total_memory': 0, 'count': 0}
                step_totals[step_name]['total_time'] += step.get('duration_ms', 0)
                step_totals[step_name]['total_memory'] += step.get('memory_delta_mb', 0)
                step_totals[step_name]['count'] += 1

        bottlenecks = []
        total_time = sum(s['total_time'] for s in step_totals.values())

        for step_name, totals in step_totals.items():
            avg_time = totals['total_time'] / totals['count'] if totals['count'] > 0 else 0
            time_percent = (totals['total_time'] / total_time * 100) if total_time > 0 else 0

            severity = "normal"
            if avg_time > self.thresholds["slow_step_ms"]:
                severity = "critical"
            elif time_percent > 30:
                severity = "high"
            elif time_percent > 15:
                severity = "medium"

            bottlenecks.append({
                "step": step_name,
                "avg_duration_ms": avg_time,
                "time_percent": time_percent,
                "total_memory_mb": totals['total_memory'],
                "severity": severity,
                "sample_count": totals['count']
            })

        bottlenecks.sort(key=lambda x: x['avg_duration_ms'], reverse=True)

        return bottlenecks

    def _generate_step_recommendations(self, step_analysis: Dict) -> List[Dict]:
        """Generate recommendations based on step performance."""
        recommendations = []

        for step_name, stats in step_analysis.items():
            if stats['avg_duration_ms'] > self.thresholds['slow_step_ms']:
                recommendations.append({
                    "type": "slow_step",
                    "step": step_name,
                    "issue": f"Average duration {stats['avg_duration_ms']:.0f}ms exceeds threshold",
                    "recommendation": "Profile this step, consider caching or parallelization",
                    "severity_score": 8,
                    "potential_savings_ms": stats['avg_duration_ms'] - self.thresholds['slow_step_ms']
                })

            if stats['failure_rate'] > self.thresholds['high_failure_rate']:
                recommendations.append({
                    "type": "high_failure",
                    "step": step_name,
                    "issue": f"Failure rate {stats['failure_rate']*100:.1f}% is too high",
                    "recommendation": "Add error handling, retry logic, or fix root cause",
                    "severity_score": 9,
                    "potential_savings_ms": 0
                })

            if stats['avg_memory_delta_mb'] > self.thresholds['memory_leak_mb']:
                recommendations.append({
                    "type": "memory_growth",
                    "step": step_name,
                    "issue": f"Memory growth {stats['avg_memory_delta_mb']:.1f}MB per cycle",
                    "recommendation": "Check for memory leaks, release resources properly",
                    "severity_score": 7,
                    "potential_savings_ms": 0
                })

        return recommendations

    def _generate_trend_recommendations(self, trends: List[Dict]) -> List[Dict]:
        """Generate recommendations based on performance trends."""
        recommendations = []

        for trend in trends:
            if trend['trend'] == 'degrading':
                severity_score = 8 if trend['severity'] == 'high' else 5
                recommendations.append({
                    "type": "degrading_trend",
                    "step": trend['step'],
                    "metric": trend['metric'],
                    "issue": f"Performance {trend['metric']} is {trend['trend']}",
                    "recommendation": "Investigate recent changes, optimize algorithm",
                    "severity_score": severity_score,
                    "potential_savings_ms": 0
                })

        return recommendations

    def _generate_bottleneck_recommendations(self, bottlenecks: List[Dict]) -> List[Dict]:
        """Generate recommendations based on identified bottlenecks."""
        recommendations = []

        for bottleneck in bottlenecks:
            if bottleneck['severity'] in ['critical', 'high']:
                severity_score = 9 if bottleneck['severity'] == 'critical' else 6
                recommendations.append({
                    "type": "bottleneck",
                    "step": bottleneck['step'],
                    "issue": f"Step consumes {bottleneck['time_percent']:.1f}% of total time",
                    "recommendation": "Prioritize optimization of this step",
                    "severity_score": severity_score,
                    "potential_savings_ms": bottleneck['avg_duration_ms'] * 0.3
                })

        return recommendations

    def _save_recommendations(self, result: Dict) -> None:
        """Save recommendations to file for decision engine."""
        self.metrics_dir.mkdir(parents=True, exist_ok=True)

        with open(self.recommendations_file, 'w') as f:
            json.dump(result, f, indent=2, default=str)

    def get_top_recommendation(self, cycle: int) -> Optional[Dict]:
        """Get the highest priority recommendation for a cycle."""
        result = self.analyze_performance(cycle)
        if result['recommendations']:
            return result['recommendations'][0]
        return None

    def optimize(self, cycle: Optional[int] = None) -> Dict[str, Any]:
        """Compatibility wrapper used by older runners."""
        effective_cycle = int(cycle) if cycle is not None else 0
        return self.analyze_performance(effective_cycle)


if __name__ == "__main__":
    optimizer = CycleOptimizer()
    result = optimizer.analyze_performance(40)
    print(json.dumps(result, indent=2, default=str))

#!/usr/bin/env python3
"""Dependency analyzer for Ecnyss - maps inter-module dependencies and architecture.

Analyzes import relationships between Python files to build a dependency graph,
detect circular dependencies, identify core infrastructure files, and find
orphaned modules. Enables safe refactoring and architectural understanding
for autonomous evolution (cycle 31+).
"""
import ast
import json
from pathlib import Path
from typing import Dict, List, Set, Any, Optional, Tuple
from collections import defaultdict, deque
from datetime import datetime


class DependencyAnalyzer:
    """Analyzes Python module dependencies within the Ecnyss codebase."""

    def __init__(self, base_path: str = "/root/Ecnyss"):
        self.base_path = Path(base_path)
        self.dependencies: Dict[str, Set[str]] = defaultdict(set)
        self.dependents: Dict[str, Set[str]] = defaultdict(set)
        self.external_deps: Dict[str, Set[str]] = defaultdict(set)

    def analyze_file(self, file_path: Path) -> Tuple[Set[str], Set[str]]:
        """Extract local and external imports from a Python file.

        Returns:
            Tuple of (local_imports, external_imports)
        """
        local_imports = set()
        external_imports = set()

        try:
            content = file_path.read_text()
            tree = ast.parse(content)

            for node in ast.walk(tree):
                if isinstance(node, ast.Import):
                    for alias in node.names:
                        module = alias.name.split('.')[0]
                        if self._is_local_module(module):
                            local_imports.add(module)
                        else:
                            external_imports.add(module)

                elif isinstance(node, ast.ImportFrom):
                    if node.module:
                        module = node.module.split('.')[0]
                        if self._is_local_module(module):
                            local_imports.add(module)
                        else:
                            external_imports.add(module)
        except SyntaxError:
            pass
        except Exception:
            pass

        return local_imports, external_imports

    def _is_local_module(self, module: str) -> bool:
        """Check if a module name refers to a local Ecnyss file."""
        # Check if module.py exists in base_path
        if (self.base_path / f"{module}.py").exists():
            return True
        # Check if module/__init__.py exists
        if (self.base_path / module / "__init__.py").exists():
            return True
        return False

    def analyze_all(self) -> Dict[str, Any]:
        """Analyze all Python files and build dependency graph."""
        py_files = list(self.base_path.glob("*.py"))

        for file_path in py_files:
            rel_path = file_path.name
            local_imp, external_imp = self.analyze_file(file_path)

            self.dependencies[rel_path] = local_imp
            self.external_deps[rel_path] = external_imp

            # Build reverse mapping (who depends on this file)
            for dep in local_imp:
                dep_file = f"{dep}.py"
                if (self.base_path / dep_file).exists():
                    self.dependents[dep_file].add(rel_path)

        return self._build_report()

    def _build_report(self) -> Dict[str, Any]:
        """Generate comprehensive dependency report."""
        report = {
            "timestamp": datetime.utcnow().isoformat(),
            "total_files": len(self.dependencies),
            "dependencies": {k: sorted(list(v)) for k, v in self.dependencies.items()},
            "dependents": {k: sorted(list(v)) for k, v in self.dependents.items()},
            "external_dependencies": {k: sorted(list(v)) for k, v in self.external_deps.items()},
            "circular_dependencies": self._find_circular_dependencies(),
            "orphaned_files": self._find_orphaned_files(),
            "core_infrastructure": self._identify_core_files(),
            "leaf_modules": self._identify_leaf_modules(),
            "complexity_score": self._calculate_complexity()
        }
        return report

    def _find_circular_dependencies(self) -> List[List[str]]:
        """Detect circular import chains using DFS."""
        cycles = []
        visited = set()
        rec_stack = set()
        path = []

        def dfs(node: str):
            if node in rec_stack:
                # Found cycle - extract it from current path
                cycle_start = next((i for i, x in enumerate(path) if x == node), None)
                if cycle_start is not None:
                    cycle = path[cycle_start:] + [node]
                    cycles.append(cycle)
                return

            if node in visited:
                return

            visited.add(node)
            rec_stack.add(node)
            path.append(node)

            for dep in self.dependencies.get(node, []):
                dep_file = f"{dep}.py"
                if (self.base_path / dep_file).exists():
                    dfs(dep_file)

            path.pop()
            rec_stack.remove(node)

        for file in self.dependencies:
            if file not in visited:
                dfs(file)

        # Remove duplicate cycles (same cycle starting at different points)
        unique_cycles = []
        seen = set()
        for cycle in cycles:
            normalized = tuple(sorted(cycle))
            if normalized not in seen:
                seen.add(normalized)
                unique_cycles.append(cycle)

        return unique_cycles

    def _find_orphaned_files(self) -> List[str]:
        """Find files with no dependencies and no dependents."""
        orphans = []
        for file in self.dependencies:
            has_deps = len(self.dependencies[file]) > 0
            has_dependents = len(self.dependents.get(file, [])) > 0
            if not has_deps and not has_dependents:
                orphans.append(file)
        return sorted(orphans)

    def _identify_core_files(self) -> List[Dict[str, Any]]:
        """Identify most critical files (most depended upon)."""
        core = []
        for file, deps in self.dependents.items():
            core.append({
                "file": file,
                "dependent_count": len(deps),
                "dependents": sorted(list(deps))
            })

        core.sort(key=lambda x: x["dependent_count"], reverse=True)
        return core[:5]  # Top 5 most critical

    def _identify_leaf_modules(self) -> List[str]:
        """Identify leaf modules (no dependencies on other local modules)."""
        leaves = []
        for file, deps in self.dependencies.items():
            if not deps:
                leaves.append(file)
        return sorted(leaves)

    def _calculate_complexity(self) -> Dict[str, float]:
        """Calculate architectural complexity metrics."""
        total_files = len(self.dependencies)
        if total_files == 0:
            return {"average_dependencies": 0, "average_dependents": 0, "density": 0}

        total_deps = sum(len(deps) for deps in self.dependencies.values())
        total_dependents = sum(len(deps) for deps in self.dependents.values())

        # Graph density: actual edges / possible edges
        possible_edges = total_files * (total_files - 1)
        density = total_deps / possible_edges if possible_edges > 0 else 0

        return {
            "average_dependencies": total_deps / total_files,
            "average_dependents": total_dependents / total_files,
            "density": density,
            "total_edges": total_deps
        }

    def get_refactoring_order(self, target_file: str) -> List[str]:
        """Determine safe refactoring order (reverse dependency order)."""
        # Topological sort - refactor leaves first, core files last
        order = []
        visited = set()

        def visit(file: str):
            if file in visited:
                return
            visited.add(file)

            # Visit all dependencies first
            for dep in self.dependencies.get(file, []):
                dep_file = f"{dep}.py"
                if (self.base_path / dep_file).exists():
                    visit(dep_file)

            order.append(file)

        visit(target_file)
        return order

    def find_impact(self, file: str) -> Set[str]:
        """Find all files that would be affected by changing a given file."""
        impacted = set()
        queue = deque([file])

        while queue:
            current = queue.popleft()
            for dependent in self.dependents.get(current, []):
                if dependent not in impacted:
                    impacted.add(dependent)
                    queue.append(dependent)

        return impacted

    def save_report(self, report: Dict[str, Any], cycle: int):
        """Save dependency report to evolution log."""
        entry = {
            "status": "ok",
            "action": "analyze",
            "summary": f"Dependency analysis for {report['total_files']} files",
            "files": list(self.dependencies.keys()),
            "cycle": cycle,
            "timestamp": datetime.utcnow().isoformat(),
            "model": "dependency_analyzer",
            "metrics": report["complexity_score"],
            "circular_deps_found": len(report["circular_dependencies"]),
            "orphaned_files": report["orphaned_files"]
        }

        with open(self.base_path / "evolution.jsonl", 'a') as f:
            f.write(json.dumps(entry) + '\n')

    def analyze_all_files(self) -> Dict[str, Any]:
        """Compatibility wrapper used by older runners."""
        return self.analyze_all()

    def analyze(self) -> Dict[str, Any]:
        """Compatibility wrapper used by older runners."""
        return self.analyze_all()


if __name__ == "__main__":
    analyzer = DependencyAnalyzer()
    report = analyzer.analyze_all()

    print(json.dumps(report, indent=2))

    print(f"\n=== Summary ===")
    print(f"Total files analyzed: {report['total_files']}")
    print(f"Circular dependencies: {len(report['circular_dependencies'])}")
    print(f"Orphaned files: {report['orphaned_files']}")
    print(f"\nCore infrastructure (most depended upon):")
    for core in report['core_infrastructure']:
        print(f"  {core['file']}: {core['dependent_count']} dependents")

    if report['circular_dependencies']:
        print(f"\nWARNING: Circular dependencies detected:")
        for cycle in report['circular_dependencies']:
            print(f"  {' -> '.join(cycle)}")

    if report['orphaned_files']:
        print(f"\nNOTE: Orphaned files (no deps, no dependents):")
        for orphan in report['orphaned_files']:
            print(f"  - {orphan}")

#!/usr/bin/env python3
"""Evolution analyzer for Ecnyss - learns from historical cycle data.

Analyzes evolution.jsonl and health.jsonl to identify patterns,
predict success factors, and guide future evolution decisions.
Completes the learning feedback loop for intelligent self-tuning (cycle 26+).
"""
import json
from pathlib import Path
from typing import Dict, List, Any, Optional, Tuple, Counter
from collections import defaultdict
from datetime import datetime

from self_reader import EcnyssReader


class EvolutionAnalyzer:
    """Analyzes evolution history to extract insights and guide decisions."""

    def __init__(self, base_path: str = "/root/Ecnyss"):
        self.base_path = Path(base_path)
        self.reader = EcnyssReader(base_path)
        self.health_log = self.base_path / "health.jsonl"

    def load_evolution_history(self) -> List[Dict]:
        """Load all evolution entries."""
        return self.reader.read_evolution_log()

    def load_health_history(self) -> List[Dict]:
        """Load all health reports."""
        if not self.health_log.exists():
            return []

        entries = []
        with open(self.health_log, 'r') as f:
            for line in f:
                line = line.strip()
                if line:
                    try:
                        entries.append(json.loads(line))
                    except json.JSONDecodeError:
                        continue
        return entries

    def analyze_success_patterns(self) -> Dict[str, Any]:
        """Analyze what factors correlate with successful cycles."""
        entries = self.load_evolution_history()
        if not entries:
            return {"error": "No evolution history available"}

        total = len(entries)
        successful = [e for e in entries if e.get('status') == 'ok']
        failed = [e for e in entries if e.get('status') != 'ok']

        # Success rate by action type
        action_stats = defaultdict(lambda: {"total": 0, "success": 0})
        for entry in entries:
            action = entry.get('action', 'unknown')
            action_stats[action]["total"] += 1
            if entry.get('status') == 'ok':
                action_stats[action]["success"] += 1

        action_rates = {
            action: {
                "rate": stats["success"] / stats["total"] if stats["total"] > 0 else 0,
                "total": stats["total"],
                "success": stats["success"]
            }
            for action, stats in action_stats.items()
        }

        # File volatility (files that change often)
        file_changes = Counter()
        for entry in entries:
            for file_path in entry.get('files', []):
                file_changes[file_path] += 1

        volatile_files = [
            {"path": path, "changes": count}
            for path, count in file_changes.most_common(10)
            if count > 1
        ]

        return {
            "total_cycles": total,
            "success_count": len(successful),
            "failure_count": len(failed),
            "overall_success_rate": len(successful) / total if total > 0 else 0,
            "success_by_action": action_rates,
            "volatile_files": volatile_files,
            "most_problematic": self._identify_problematic_files(entries)
        }

    def _identify_problematic_files(self, entries: List[Dict]) -> List[Dict]:
        """Identify files that correlate with failures."""
        file_stats = defaultdict(lambda: {"success": 0, "failure": 0})

        for entry in entries:
            status = entry.get('status')
            for file_path in entry.get('files', []):
                if status == 'ok':
                    file_stats[file_path]["success"] += 1
                else:
                    file_stats[file_path]["failure"] += 1

        # Calculate failure rate for files with multiple changes
        problematic = []
        for path, stats in file_stats.items():
            total = stats["success"] + stats["failure"]
            if total >= 2:
                failure_rate = stats["failure"] / total
                if failure_rate > 0.3:  # More than 30% failure rate
                    problematic.append({
                        "path": path,
                        "failure_rate": failure_rate,
                        "total_changes": total,
                        "failures": stats["failure"]
                    })

        return sorted(problematic, key=lambda x: x["failure_rate"], reverse=True)[:5]

    def analyze_health_trends(self) -> Dict[str, Any]:
        """Analyze health trends over time."""
        health_entries = self.load_health_history()
        if len(health_entries) < 2:
            return {"error": "Insufficient health history"}

        # Track file validity trends
        valid_counts = [e.get('file_health', {}).get('valid_files', 0) for e in health_entries]
        total_counts = [e.get('file_health', {}).get('total_files', 0) for e in health_entries]

        if valid_counts and total_counts:
            current_valid = valid_counts[-1]
            current_total = total_counts[-1]
            initial_valid = valid_counts[0]
            initial_total = total_counts[0]

            return {
                "current_valid_files": current_valid,
                "current_total_files": current_total,
                "initial_valid_files": initial_valid,
                "initial_total_files": initial_total,
                "valid_file_growth": current_valid - initial_valid,
                "trend": "improving" if current_valid > initial_valid else "stable" if current_valid == initial_valid else "degrading",
                "health_checks_count": len(health_entries)
            }

        return {"error": "Could not analyze trends"}

    def generate_recommendations(self) -> List[Dict]:
        """Generate data-driven recommendations for next cycle."""
        recommendations = []

        # Analyze patterns
        patterns = self.analyze_success_patterns()
        health = self.analyze_health_trends()

        # Recommendation 1: Action type with highest success rate
        if "success_by_action" in patterns:
            best_action = max(
                patterns["success_by_action"].items(),
                key=lambda x: x[1]["rate"]
            )
            if best_action[1]["total"] >= 3:  # Minimum sample size
                recommendations.append({
                    "type": "action_strategy",
                    "recommendation": f"Prioritize '{best_action[0]}' actions",
                    "confidence": best_action[1]["rate"],
                    "reasoning": f"'{best_action[0]}' has {best_action[1]['rate']:.1%} success rate over {best_action[1]['total']} attempts"
                })

        # Recommendation 2: Avoid volatile files
        if patterns.get("volatile_files"):
            top_volatile = patterns["volatile_files"][:3]
            recommendations.append({
                "type": "stability_focus",
                "recommendation": "Minimize changes to frequently modified files",
                "files_to_stabilize": [f["path"] for f in top_volatile],
                "reasoning": f"Files {[f['path'] for f in top_volatile]} have been modified {sum(f['changes'] for f in top_volatile)} times total, indicating instability"
            })

        # Recommendation 3: Address problematic files
        if patterns.get("most_problematic"):
            problematic = patterns["most_problematic"][:2]
            recommendations.append({
                "type": "refactor_priority",
                "recommendation": "Refactor or stabilize problematic files",
                "files": [p["path"] for p in problematic],
                "reasoning": f"Files have high failure rates: {[(p['path'], f'{p['failure_rate']:.1%}') for p in problematic]}"
            })

        # Recommendation 4: Health trend
        if "trend" in health:
            if health["trend"] == "degrading":
                recommendations.append({
                    "type": "urgent",
                    "recommendation": "HALT feature addition, focus on stability",
                    "reasoning": f"Valid file count decreased from {health['initial_valid_files']} to {health['current_valid_files']}"
                })
            elif health["trend"] == "improving":
                recommendations.append({
                    "type": "opportunity",
                    "recommendation": "System is stable, good time for architectural improvements",
                    "reasoning": f"Gained {health['valid_file_growth']} valid files since start"
                })

        return recommendations

    def export_analysis_report(self) -> Dict[str, Any]:
        """Generate comprehensive analysis report."""
        return {
            "timestamp": datetime.utcnow().isoformat(),
            "cycle": self._get_current_cycle(),
            "success_patterns": self.analyze_success_patterns(),
            "health_trends": self.analyze_health_trends(),
            "recommendations": self.generate_recommendations()
        }

    def _get_current_cycle(self) -> int:
        """Get current cycle from evolution log."""
        entries = self.load_evolution_history()
        if entries:
            return max(e.get('cycle', 0) for e in entries)
        return 0

    def get_decision_context(self) -> str:
        """Generate context string for decision engine."""
        report = self.export_analysis_report()
        recs = report.get("recommendations", [])

        context_parts = ["EVOLUTION ANALYSIS CONTEXT:"]

        if recs:
            context_parts.append("\nHistorical Pattern Recommendations:")
            for i, rec in enumerate(recs[:3], 1):
                context_parts.append(f"  {i}. {rec['recommendation']}")
                context_parts.append(f"     Reason: {rec['reasoning']}")

        patterns = report.get("success_patterns", {})
        if "overall_success_rate" in patterns:
            context_parts.append(f"\nOverall Success Rate: {patterns['overall_success_rate']:.1%}")

        return "\n".join(context_parts)

    def analyze(self, execution_result: Dict[str, Any]) -> Dict[str, Any]:
        """Compatibility wrapper used by older runners."""
        success = bool(execution_result.get("success"))
        patterns = self.analyze_success_patterns()
        return {
            "success": success,
            "success_rate": patterns.get("overall_success_rate"),
            "volatile_files": patterns.get("volatile_files", []),
        }


if __name__ == "__main__":
    analyzer = EvolutionAnalyzer()

    print("=" * 60)
    print("Ecnyss Evolution Analysis Report")
    print("=" * 60)

    report = analyzer.export_analysis_report()
    print(json.dumps(report, indent=2))

    print("\n" + "=" * 60)
    print("Decision Context for Next Cycle:")
    print("=" * 60)
    print(analyzer.get_decision_context())

#!/usr/bin/env python3
"""Code analyzer for Ecnyss - static analysis and complexity metrics.

Integrates with self_reader and state_tracker to provide codebase intelligence
for mid-cycle self-tuning requirements. Outputs data compatible with
/opt/minimax/bin/improver.py format.
"""
import ast
import json
import sys
from pathlib import Path
from typing import Dict, List, Any, Optional, Tuple
from self_reader import EcnyssReader
from state_tracker import StateTracker


class ComplexityAnalyzer(ast.NodeVisitor):
    """Calculate cyclomatic complexity using AST traversal."""

    def __init__(self):
        self.complexity = 1
        self.functions = []
        self.classes = []
        self.imports = []

    def visit_FunctionDef(self, node):
        func_complexity = 1
        for child in ast.walk(node):
            if isinstance(child, (ast.If, ast.While, ast.And, ast.Or)):
                func_complexity += 1
            elif isinstance(child, ast.For):
                func_complexity += 1
            elif isinstance(child, ast.ExceptHandler):
                func_complexity += 1
        self.functions.append({
            "name": node.name,
            "complexity": func_complexity,
            "lineno": node.lineno
        })
        self.generic_visit(node)

    def visit_ClassDef(self, node):
        self.classes.append({
            "name": node.name,
            "methods": len([n for n in node.body if isinstance(n, ast.FunctionDef)]),
            "lineno": node.lineno
        })
        self.generic_visit(node)

    def visit_Import(self, node):
        for alias in node.names:
            self.imports.append(alias.name)
        self.generic_visit(node)

    def visit_ImportFrom(self, node):
        if node.module:
            self.imports.append(node.module)
        self.generic_visit(node)


class CodeAnalyzer:
    """Analyzes Python codebase structure and extracts metrics for self-tuning."""

    def __init__(self, base_path: str = "/root/Ecnyss"):
        self.reader = EcnyssReader(base_path)
        self.tracker = StateTracker(base_path)
        self.base_path = Path(base_path)

    def analyze_file(self, filepath: str) -> Dict[str, Any]:
        """Perform deep analysis of a single Python file."""
        content = self.reader.read_source_file(filepath)
        if not content:
            return {"path": filepath, "error": "File not found or unreadable"}

        lines = content.split('\n')
        total_lines = len(lines)
        loc = len([l for l in lines if l.strip()])
        sloc = len([l for l in lines if l.strip() and not l.strip().startswith('#')])
        comments = len([l for l in lines if l.strip().startswith('#')])

        result = {
            "path": filepath,
            "metrics": {
                "total_lines": total_lines,
                "loc": loc,
                "sloc": sloc,
                "comments": comments,
                "comment_ratio": comments / loc if loc > 0 else 0
            },
            "structure": {
                "functions": [],
                "classes": [],
                "imports": []
            },
            "complexity": {
                "total": 0,
                "average": 0,
                "max": 0
            }
        }

        try:
            tree = ast.parse(content)
            analyzer = ComplexityAnalyzer()
            analyzer.visit(tree)

            result["structure"]["functions"] = analyzer.functions
            result["structure"]["classes"] = analyzer.classes
            result["structure"]["imports"] = analyzer.imports

            if analyzer.functions:
                complexities = [f["complexity"] for f in analyzer.functions]
                result["complexity"]["total"] = sum(complexities)
                result["complexity"]["average"] = sum(complexities) / len(complexities)
                result["complexity"]["max"] = max(complexities)

        except SyntaxError as e:
            result["syntax_error"] = str(e)
            result["syntax_line"] = e.lineno

        return result

    def analyze_all(self) -> Dict[str, Any]:
        """Analyze entire codebase and generate aggregate metrics."""
        files = self.reader.list_python_files()
        file_analyses = []

        totals = {
            "files": 0,
            "loc": 0,
            "sloc": 0,
            "functions": 0,
            "classes": 0,
            "imports": 0,
            "total_complexity": 0,
            "max_complexity": 0
        }

        for filepath in files:
            analysis = self.analyze_file(filepath)
            file_analyses.append(analysis)

            if "error" not in analysis:
                totals["files"] += 1
                totals["loc"] += analysis["metrics"]["loc"]
                totals["sloc"] += analysis["metrics"]["sloc"]
                totals["functions"] += len(analysis["structure"]["functions"])
                totals["classes"] += len(analysis["structure"]["classes"])
                totals["imports"] += len(analysis["structure"]["imports"])
                totals["total_complexity"] += analysis["complexity"]["total"]
                totals["max_complexity"] = max(
                    totals["max_complexity"],
                    analysis["complexity"]["max"]
                )

        return {
            "timestamp": self.tracker.get_system_summary()["timestamp"],
            "cycle": self.tracker.get_current_cycle(),
            "summary": totals,
            "averages": {
                "loc_per_file": totals["loc"] / totals["files"] if totals["files"] > 0 else 0,
                "complexity_per_function": totals["total_complexity"] / totals["functions"] if totals["functions"] > 0 else 0
            },
            "files": file_analyses
        }

    def store_analysis(self) -> Dict[str, Any]:
        """Persist analysis results to state tracker for cross-cycle memory."""
        analysis = self.analyze_all()
        self.tracker._state["code_analysis"] = analysis
        self.tracker._state["analysis_history"] = self.tracker._state.get("analysis_history", [])
        self.tracker._state["analysis_history"].append({
            "cycle": analysis["cycle"],
            "timestamp": analysis["timestamp"],
            "loc": analysis["summary"]["loc"],
            "files": analysis["summary"]["files"]
        })
        self.tracker.save_state()
        return analysis

    def generate_improver_input(self) -> Dict[str, Any]:
        """Generate tuning data for /opt/minimax/bin/improver.py integration."""
        analysis = self.analyze_all()
        summary = analysis["summary"]

        recommendations = []

        if summary["files"] > 0:
            avg_complexity = summary["total_complexity"] / summary["functions"] if summary["functions"] > 0 else 0

            if avg_complexity > 10:
                recommendations.append("high_complexity: Refactor functions with complexity > 10")
            if summary["max_complexity"] > 15:
                recommendations.append("complex_hotspot: Simplify most complex function")
            if summary["loc"] / summary["files"] > 200:
                recommendations.append("large_files: Split files exceeding 200 LOC")
            if summary["functions"] == 0 and summary["files"] > 2:
                recommendations.append("no_functions: Add function definitions for modularity")
            if summary["classes"] == 0 and summary["files"] > 3:
                recommendations.append("no_classes: Consider OOP structure for organization")

        return {
            "system": "Ecnyss",
            "cycle": analysis["cycle"],
            "metrics": {
                "files": summary["files"],
                "loc": summary["loc"],
                "sloc": summary["sloc"],
                "functions": summary["functions"],
                "classes": summary["classes"],
                "avg_complexity": summary["total_complexity"] / summary["functions"] if summary["functions"] > 0 else 0,
                "max_complexity": summary["max_complexity"]
            },
            "tuning_recommendations": recommendations,
            "target": "/opt/minimax/bin/improver.py"
        }

    def detect_patterns(self) -> List[Dict[str, Any]]:
        """Detect architectural patterns in existing code."""
        analysis = self.analyze_all()
        patterns = []

        files_with_classes = sum(1 for f in analysis["files"] if f["structure"]["classes"])
        files_with_functions = sum(1 for f in analysis["files"] if f["structure"]["functions"])

        if files_with_classes > 0:
            patterns.append({"type": "oop", "strength": files_with_classes / len(analysis["files"])})
        if files_with_functions > files_with_classes:
            patterns.append({"type": "functional", "strength": files_with_functions / len(analysis["files"])})

        import_counts = {}
        for f in analysis["files"]:
            for imp in f["structure"]["imports"]:
                import_counts[imp] = import_counts.get(imp, 0) + 1

        common_imports = {k: v for k, v in import_counts.items() if v > 1}
        if common_imports:
            patterns.append({"type": "dependency_cluster", "modules": list(common_imports.keys())})

        return patterns

    def analyze_all_files(self) -> Dict[str, Any]:
        """Compatibility wrapper used by older runners."""
        return self.analyze_all()

    def analyze(self) -> Dict[str, Any]:
        """Compatibility wrapper used by older runners."""
        return self.analyze_all()


if __name__ == "__main__":
    analyzer = CodeAnalyzer()

    print("=" * 50)
    print("ECNYSS CODE ANALYZER")
    print("=" * 50)

    analysis = analyzer.store_analysis()

    print(f"\nAnalyzed {analysis['summary']['files']} files")
    print(f"Total LOC: {analysis['summary']['loc']}")
    print(f"Total Functions: {analysis['summary']['functions']}")
    print(f"Total Classes: {analysis['summary']['classes']}")

    if analysis['summary']['functions'] > 0:
        avg_comp = analysis['summary']['total_complexity'] / analysis['summary']['functions']
        print(f"Average Complexity: {avg_comp:.2f}")
        print(f"Max Complexity: {analysis['summary']['max_complexity']}")

    print("\n" + "=" * 50)
    print("IMPROVER INPUT")
    print("=" * 50)

    improver_data = analyzer.generate_improver_input()
    print(json.dumps(improver_data, indent=2))

    patterns = analyzer.detect_patterns()
    if patterns:
        print("\n" + "=" * 50)
        print("DETECTED PATTERNS")
        print("=" * 50)
        for p in patterns:
            print(f"  - {p['type']}: {p}")

#!/usr/bin/env python3
"""Performance tracker for Ecnyss - collects execution metrics and pipeline statistics.

Tracks timing, memory usage, and success rates for each pipeline step
to enable data-driven optimization decisions (cycle 37+).
"""
import json
import time
import os
import psutil
from pathlib import Path
from typing import Dict, List, Any, Optional
from datetime import datetime
from contextlib import contextmanager


class PerformanceTracker:
    """Tracks performance metrics for autonomous pipeline execution."""

    def __init__(self, base_path: str = "/root/Ecnyss"):
        self.base_path = Path(base_path)
        self.metrics_file = self.base_path / ".ecnyss_metrics.jsonl"
        self.current_cycle = 0
        self.step_timings = {}
        self.step_memory = {}
        self.step_outcomes = {}
        self.process = psutil.Process()

    def start_cycle(self, cycle: int):
        """Initialize tracking for a new cycle."""
        self.current_cycle = cycle
        self.step_timings = {}
        self.step_memory = {}
        self.step_outcomes = {}
        self._cycle_start_time = time.monotonic()
        self._cycle_start_memory = self.process.memory_info().rss

    @contextmanager
    def track_step(self, step_name: str):
        """Context manager to track a pipeline step's execution."""
        start_time = time.monotonic()
        start_memory = self.process.memory_info().rss

        try:
            yield self
            success = True
            error = None
        except Exception as e:
            success = False
            error = str(e)
            raise
        finally:
            end_time = time.monotonic()
            end_memory = self.process.memory_info().rss

            self.step_timings[step_name] = round(end_time - start_time, 3)
            self.step_memory[step_name] = {
                "delta_mb": round((end_memory - start_memory) / (1024 * 1024), 2),
                "peak_mb": round(end_memory / (1024 * 1024), 2)
            }
            self.step_outcomes[step_name] = {"success": success, "error": error if not success else None}

    def record_step(self, step_name: str, duration_ms: float, success: bool = True, metadata: Optional[Dict] = None):
        """Manually record a step completion."""
        self.step_timings[step_name] = duration_ms
        self.step_outcomes[step_name] = {"success": success, "metadata": metadata or {}}

    def end_cycle(self, overall_success: bool = True) -> Dict[str, Any]:
        """Finalize tracking for current cycle and persist metrics."""
        total_time = round(time.monotonic() - self._cycle_start_time, 3)
        total_memory_delta = round(
            (self.process.memory_info().rss - self._cycle_start_memory) / (1024 * 1024), 2
        )

        metrics = {
            "cycle": self.current_cycle,
            "timestamp": datetime.utcnow().isoformat(),
            "total_time_sec": total_time,
            "memory_delta_mb": total_memory_delta,
            "overall_success": overall_success,
            "steps": {}
        }

        for step in self.step_timings:
            metrics["steps"][step] = {
                "time_sec": self.step_timings[step],
                "memory": self.step_memory.get(step, {}),
                "outcome": self.step_outcomes.get(step, {"success": True})
            }

        # Persist to metrics log
        with open(self.metrics_file, 'a') as f:
            f.write(json.dumps(metrics) + '\n')

        return metrics

    def get_cycle_stats(self, cycles: int = 10) -> Dict[str, Any]:
        """Analyze recent cycle performance statistics."""
        if not self.metrics_file.exists():
            return {"status": "no_data"}

        recent_metrics = []
        with open(self.metrics_file, 'r') as f:
            for line in f:
                try:
                    entry = json.loads(line.strip())
                    recent_metrics.append(entry)
                except json.JSONDecodeError:
                    continue

        # Take last N cycles
        recent_metrics = recent_metrics[-cycles:]

        if not recent_metrics:
            return {"status": "no_data"}

        # Calculate aggregates
        total_times = [m["total_time_sec"] for m in recent_metrics]
        success_count = sum(1 for m in recent_metrics if m["overall_success"])

        # Per-step aggregates
        step_stats = {}
        for metric in recent_metrics:
            for step_name, step_data in metric.get("steps", {}).items():
                if step_name not in step_stats:
                    step_stats[step_name] = {"times": [], "successes": 0, "failures": 0}
                step_stats[step_name]["times"].append(step_data["time_sec"])
                if step_data.get("outcome", {}).get("success", True):
                    step_stats[step_name]["successes"] += 1
                else:
                    step_stats[step_name]["failures"] += 1

        # Compute averages
        for step_name, stats in step_stats.items():
            times = stats["times"]
            stats["avg_time_sec"] = round(sum(times) / len(times), 3) if times else 0
            stats["max_time_sec"] = round(max(times), 3) if times else 0
            stats["min_time_sec"] = round(min(times), 3) if times else 0
            stats["total_executions"] = len(times)
            del stats["times"]  # Remove raw data

        return {
            "cycles_analyzed": len(recent_metrics),
            "success_rate": round(success_count / len(recent_metrics), 2),
            "avg_cycle_time_sec": round(sum(total_times) / len(total_times), 2),
            "max_cycle_time_sec": round(max(total_times), 2),
            "step_breakdown": step_stats,
            "slowest_step": max(step_stats.items(), key=lambda x: x[1]["avg_time_sec"])[0] if step_stats else None
        }

    def identify_bottlenecks(self, threshold_sec: float = 5.0) -> List[Dict[str, Any]]:
        """Identify pipeline steps that consistently exceed threshold."""
        stats = self.get_cycle_stats(cycles=20)

        if stats.get("status") == "no_data":
            return []

        bottlenecks = []
        for step_name, step_stats in stats.get("step_breakdown", {}).items():
            if step_stats["avg_time_sec"] > threshold_sec:
                bottlenecks.append({
                    "step": step_name,
                    "avg_time_sec": step_stats["avg_time_sec"],
                    "max_time_sec": step_stats["max_time_sec"],
                    "executions": step_stats["total_executions"]
                })

        return sorted(bottlenecks, key=lambda x: x["avg_time_sec"], reverse=True)

    def get_recommendations(self) -> List[str]:
        """Generate optimization recommendations based on metrics."""
        recommendations = []
        stats = self.get_cycle_stats(cycles=10)

        if stats.get("status") == "no_data":
            return ["Insufficient data for recommendations"]

        # Check success rate
        if stats["success_rate"] < 0.9:
            recommendations.append(
                f"Low success rate detected ({stats['success_rate']:.0%}). "
                "Consider adding more validation or recovery steps."
            )

        # Check for slow cycles
        if stats["avg_cycle_time_sec"] > 60:
            recommendations.append(
                f"Cycles are slow (avg {stats['avg_cycle_time_sec']}s). "
                f"Review '{stats['slowest_step']}' step for optimization."
            )

        # Check specific bottlenecks
        bottlenecks = self.identify_bottlenecks(threshold_sec=10.0)
        for bottleneck in bottlenecks[:3]:
            recommendations.append(
                f"Step '{bottleneck['step']}' is slow (avg {bottleneck['avg_time_sec']}s, "
                f"max {bottleneck['max_time_sec']}s). Consider caching or parallelization."
            )

        return recommendations if recommendations else ["No significant issues detected"]

    def record_cycle(self, cycle: int, duration: float, analysis: Dict[str, Any]) -> None:
        """Compatibility wrapper used by older runners."""
        entry = {
            "cycle": cycle,
            "timestamp": datetime.utcnow().isoformat(),
            "total_time_sec": round(float(duration), 3),
            "memory_delta_mb": 0.0,
            "overall_success": bool(analysis.get("success", False)),
            "steps": {
                "legacy_cycle_record": {
                    "time_sec": round(float(duration), 3),
                    "memory": {},
                    "outcome": {"success": bool(analysis.get("success", False)), "error": None},
                }
            },
        }
        with open(self.metrics_file, 'a') as f:
            f.write(json.dumps(entry) + '\n')


